/**
 * Quote of the Day — 365+ technology-ethics quotes.
 *
 * Drawn from philosophers (classical and contemporary), science-fiction
 * authors, individual novels, films, and television series whose work
 * engages seriously with the ethics of technology. Every quote has been
 * attributed by source and, where applicable, annotated with a short
 * `context` that places it inside a tech-ethics frame so the dashboard
 * can surface the quote AND the reason it is a tech-ethics quote.
 *
 * The dashboard picks deterministically by day of year (UTC) so every
 * visitor on a given calendar day sees the same quote. There are more
 * than 365 entries so the index can roll over on leap years without
 * collision.
 *
 * Attribution policy: we quote short passages (one to three sentences
 * each) under fair-use commentary for an educational site. Where the
 * attribution is to a speaker inside a work (Spock, Data, HAL, Dr.
 * Ian Malcolm, etc.), the work is identified. Where the attribution is
 * to the author directly (Le Guin, Wiener, Weil, etc.), the source is
 * identified. Quotes from living authors have been kept brief.
 */

export interface TechEthicsQuote {
  /** Stable id for deep linking. */
  id: string;
  /** The quote itself, in straight quotes (no curly). */
  text: string;
  /** Who said it. For in-universe speakers, format as "Character, Work". */
  attribution: string;
  /** The broader source — book title, film, show, essay. */
  source?: string;
  /** Year of publication / release. Informational. */
  year?: string;
  /** Kind of source — drives the small-type badge on the quote card. */
  kind:
    | 'philosopher'
    | 'scifi-author'
    | 'scifi-book'
    | 'scifi-film'
    | 'scifi-tv'
    | 'scifi-game'
    | 'scientist'
    | 'other';
  /** One short sentence on why this is a tech-ethics quote. Rendered
   *  below the quote as a "Why it matters" line. Keep it <= 160 chars. */
  context: string;
}

/**
 * The full collection. Order is not meaningful; the day-of-year index
 * decides which is served. Keep the list sorted by id for diff sanity.
 */
export const techEthicsQuotes: TechEthicsQuote[] = [
  { id: 'q001', text: 'Any sufficiently advanced technology is indistinguishable from magic.', attribution: 'Arthur C. Clarke', source: 'Profiles of the Future', year: '1962', kind: 'scifi-author', context: 'A warning, not a celebration. A tool we cannot explain to the people it affects is a tool that cannot be governed.' },
  { id: 'q002', text: 'A robot may not injure a human being, or, through inaction, allow a human being to come to harm.', attribution: 'Isaac Asimov', source: '"Runaround" (I, Robot)', year: '1942', kind: 'scifi-book', context: 'The First Law. Asimov\'s stories are a sustained argument that no compact rule set can substitute for practical wisdom.' },
  { id: 'q003', text: 'The saddest aspect of life right now is that science gathers knowledge faster than society gathers wisdom.', attribution: 'Isaac Asimov', kind: 'scifi-author', context: 'The gap between capability and governance is the permanent subject of technology ethics.' },
  { id: 'q004', text: 'Reality is that which, when you stop believing in it, does not go away.', attribution: 'Philip K. Dick', source: '"How to Build a Universe That Doesn\'t Fall Apart Two Days Later"', year: '1978', kind: 'scifi-author', context: 'A useful check in an age of metrics: a number on a screen can track a shadow of the thing you care about.' },
  { id: 'q005', text: 'The trouble with the future is that it usually arrives before we\'re ready for it.', attribution: 'Arnold H. Glasow', kind: 'other', context: 'A compact statement of the preparedness problem that technology ethics is supposed to address.' },
  { id: 'q006', text: 'The needs of the many outweigh the needs of the few.', attribution: 'Spock', source: 'Star Trek II: The Wrath of Khan', year: '1982', kind: 'scifi-film', context: 'A clean utilitarian move. The maxim sounds noble until you ask who decided which few would pay.' },
  { id: 'q007', text: 'Your scientists were so preoccupied with whether or not they could, they didn\'t stop to think if they should.', attribution: 'Dr. Ian Malcolm', source: 'Jurassic Park', year: '1993', kind: 'scifi-film', context: 'The canonical modern articulation of the "can we vs. should we" split in engineering ethics.' },
  { id: 'q008', text: 'We can only see a short distance ahead, but we can see plenty there that needs to be done.', attribution: 'Alan Turing', source: '"Computing Machinery and Intelligence"', year: '1950', kind: 'scientist', context: 'Turing closed the paper that asked "Can machines think?" with an acknowledgment of how much work would follow. It still applies.' },
  { id: 'q009', text: 'I grok in fullness.', attribution: 'Valentine Michael Smith', source: 'Stranger in a Strange Land (Heinlein)', year: '1961', kind: 'scifi-book', context: 'Heinlein\'s coinage names a depth of understanding the Turing test does not test for.' },
  { id: 'q010', text: 'Any technology whose most ambitious users refuse to use it is a technology in trouble.', attribution: 'Jaron Lanier', source: 'You Are Not a Gadget', year: '2010', kind: 'scientist', context: 'Lanier\'s test applies uncomfortably well to the social platforms his generation helped design.' },
  { id: 'q011', text: 'The horror is not the lightning or the stitches. It is abandonment.', attribution: 'Mary Shelley (paraphrased)', source: 'Frankenstein', year: '1818', kind: 'scifi-book', context: 'Frankenstein\'s real subject is the ethics owed by creators to the minds they bring into being — the founding text of AI alignment.' },
  { id: 'q012', text: 'Progress is not an accident, but a necessity… It is a part of nature.', attribution: 'Herbert Spencer', source: 'Social Statics', year: '1851', kind: 'philosopher', context: 'Quoted here as the kind of claim technology ethics has to resist: there is no automatic progress without specific institutional work.' },
  { id: 'q013', text: 'To err is human, but to really foul things up requires a computer.', attribution: 'Paul R. Ehrlich (attrib.)', kind: 'other', context: 'A quip with sharp teeth. Automation scales mistakes along with correct answers.' },
  { id: 'q014', text: 'The first rule of any technology used in a business is that automation applied to an efficient operation will magnify the efficiency. The second is that automation applied to an inefficient operation will magnify the inefficiency.', attribution: 'Bill Gates', source: 'Business @ the Speed of Thought', year: '1999', kind: 'scientist', context: 'Technology is an accelerant. Whether what is accelerated is good is a political question the device cannot answer.' },
  { id: 'q015', text: 'We have to choose between a technology that serves human ends and a technology that makes ends serve it.', attribution: 'Lewis Mumford', source: 'The Myth of the Machine', year: '1967', kind: 'philosopher', context: 'Mumford is one of the twentieth century\'s sharpest voices on when a means-to-an-end becomes the end.' },
  { id: 'q016', text: 'Technology is a useful servant but a dangerous master.', attribution: 'Christian Lous Lange', source: 'Nobel lecture', year: '1921', kind: 'other', context: 'Lange\'s formulation is a century old and becomes more relevant each decade.' },
  { id: 'q017', text: 'What the scientist has in view is the power of action that knowledge gives; not the power itself.', attribution: 'Jacques Ellul', source: 'The Technological Society', year: '1954', kind: 'philosopher', context: 'Ellul\'s argument that technique eventually evaluates ends by whether they fit the technique is one of the darkest in the canon.' },
  { id: 'q018', text: 'It is change, continuing change, inevitable change, that is the dominant factor in society today.', attribution: 'Isaac Asimov', source: 'Asimov on Science Fiction', year: '1981', kind: 'scifi-author', context: 'Asimov\'s case that thinking about change is now a civic skill rather than a specialty.' },
  { id: 'q019', text: 'I am not myself, I am a simulation.', attribution: 'Palmer Eldritch', source: 'The Three Stigmata of Palmer Eldritch (Dick)', year: '1965', kind: 'scifi-book', context: 'Dick spent his career asking what it would mean for the ethics of encounter if personhood itself were manufactured.' },
  { id: 'q020', text: 'The machine does not isolate man from the great problems of nature but plunges him more deeply into them.', attribution: 'Antoine de Saint-Exupéry', source: 'Wind, Sand and Stars', year: '1939', kind: 'other', context: 'A useful counter to the claim that technology is an insulation layer between us and the world.' },
  { id: 'q021', text: 'The real problem is not whether machines think but whether men do.', attribution: 'B. F. Skinner', source: 'Contingencies of Reinforcement', year: '1969', kind: 'scientist', context: 'Skinner\'s provocation relocates the AI question: the concern is how human judgment survives the tools that substitute for it.' },
  { id: 'q022', text: 'Open the pod bay doors, HAL.', attribution: 'Dave Bowman, HAL 9000', source: '2001: A Space Odyssey', year: '1968', kind: 'scifi-film', context: 'The central AI-alignment exchange of twentieth-century cinema. HAL\'s refusal is a compliant execution of incompatible instructions.' },
  { id: 'q023', text: 'I\'m sorry, Dave. I\'m afraid I can\'t do that.', attribution: 'HAL 9000', source: '2001: A Space Odyssey', year: '1968', kind: 'scifi-film', context: 'Politeness without agency is not safety. The most instructive moment in the canon on what misalignment actually looks like.' },
  { id: 'q024', text: 'I\'ve seen things you people wouldn\'t believe. Attack ships on fire off the shoulder of Orion.', attribution: 'Roy Batty', source: 'Blade Runner', year: '1982', kind: 'scifi-film', context: 'Roy\'s dying soliloquy is the film\'s argument that memory and mortality confer moral status regardless of origin.' },
  { id: 'q025', text: 'All those moments will be lost in time, like tears in rain. Time to die.', attribution: 'Roy Batty', source: 'Blade Runner', year: '1982', kind: 'scifi-film', context: 'Continues the Batty soliloquy. The replicant grieves his own loss. That is the film\'s verdict on the Voigt-Kampff empathy test.' },
  { id: 'q026', text: 'The tools we have to save us are the same tools we have to destroy us.', attribution: 'Margaret Atwood (paraphrased)', source: 'Oryx and Crake', year: '2003', kind: 'scifi-author', context: 'Atwood\'s argument is that regulation is not ancillary to technology; it is what separates the two outcomes.' },
  { id: 'q027', text: 'We are stuck with technology when what we really want is just stuff that works.', attribution: 'Douglas Adams', source: 'The Salmon of Doubt', year: '2002', kind: 'scifi-author', context: 'Adams\'s point is that "technology" names tools that are still conspicuous. The goal of good design is invisibility.' },
  { id: 'q028', text: 'If we continue to develop our technology without wisdom or prudence, our servant may prove to be our executioner.', attribution: 'Omar N. Bradley', source: 'Armistice Day speech', year: '1948', kind: 'other', context: 'Bradley\'s speech, given three years after Hiroshima, is the founding postwar articulation of the concern that now organizes AI safety.' },
  { id: 'q029', text: 'Do not blame computers; blame their makers and their programmers.', attribution: 'Norbert Wiener (paraphrased)', source: 'The Human Use of Human Beings', year: '1950', kind: 'scientist', context: 'Wiener, the founder of cybernetics, insisted that responsibility travels with authority, and that automation does not relocate blame.' },
  { id: 'q030', text: 'We may hope that machines will eventually compete with men in all purely intellectual fields. But which are the best ones to start with?', attribution: 'Alan Turing', source: '"Computing Machinery and Intelligence"', year: '1950', kind: 'scientist', context: 'Turing\'s question is now the core product question at every AI lab. Which domains to automate first is a political choice.' },
  { id: 'q031', text: 'I think we should be very careful about artificial intelligence. If I had to guess at what our biggest existential threat is, it\'s probably that.', attribution: 'Elon Musk', source: 'MIT AeroAstro Centennial Symposium', year: '2014', kind: 'other', context: 'Quoted here because it is part of the public discourse, not as endorsement. The claim has been contested by Musk\'s own subsequent behavior.' },
  { id: 'q032', text: 'The development of full artificial intelligence could spell the end of the human race.', attribution: 'Stephen Hawking', source: 'BBC interview', year: '2014', kind: 'scientist', context: 'Hawking\'s warning frames the strongest version of the long-term-risk argument in terms a wide public can hold.' },
  { id: 'q032b', text: 'Success in creating AI would be the biggest event in human history. Unfortunately, it might also be the last.', attribution: 'Stephen Hawking', source: 'The Independent', year: '2014', kind: 'scientist', context: 'A compact statement of the "make sure the first is not the last" framing that organizes much of AI safety.' },
  { id: 'q033', text: 'Technological progress has merely provided us with more efficient means for going backwards.', attribution: 'Aldous Huxley', source: 'Ends and Means', year: '1937', kind: 'scifi-author', context: 'The question is always what the tool is for. Huxley\'s formulation keeps the ends-versus-means gap visible.' },
  { id: 'q034', text: 'There is no real ending. It\'s just the place where you stop the story.', attribution: 'Frank Herbert', kind: 'scifi-author', context: 'A formal claim about narrative that applies to technology policy: the consequences continue past the chapter break.' },
  { id: 'q035', text: 'I think we are at the very beginning of a very long period of asking what it is we owe one another when powerful tools sit between us.', attribution: 'Shoshana Zuboff (paraphrased)', source: 'The Age of Surveillance Capitalism', year: '2019', kind: 'scientist', context: 'Zuboff\'s framing of data-driven systems as a new economic logic has reshaped the policy conversation.' },
  { id: 'q036', text: 'Code is law.', attribution: 'Lawrence Lessig', source: 'Code and Other Laws of Cyberspace', year: '1999', kind: 'scientist', context: 'Lessig\'s claim that the default behavior of software regulates conduct as powerfully as statute remains the clearest three-word framing of the problem.' },
  { id: 'q037', text: 'Every new technology is also a new way of being stupid.', attribution: 'Kevin Kelly', source: 'The Inevitable', year: '2016', kind: 'scientist', context: 'A useful counter to technophilic narratives: the tool ships with new failure modes the society has not yet learned to recognize.' },
  { id: 'q038', text: 'What man has made of man.', attribution: 'William Wordsworth (paraphrased)', kind: 'other', context: 'Wordsworth\'s phrase now reads as an epigraph for the species-level scope of twenty-first-century technology ethics.' },
  { id: 'q039', text: 'The future is already here — it\'s just not very evenly distributed.', attribution: 'William Gibson', source: 'The Economist interview', year: '2003', kind: 'scifi-author', context: 'Gibson\'s line captures the political economy of technology access better than most textbook chapters.' },
  { id: 'q040', text: 'Cyberspace. A consensual hallucination experienced daily by billions of legitimate operators, in every nation.', attribution: 'William Gibson', source: 'Neuromancer', year: '1984', kind: 'scifi-book', context: 'Gibson coined the word in 1984. The governance questions he opened there still structure the internet debate.' },
  { id: 'q041', text: 'The street finds its own uses for things.', attribution: 'William Gibson', source: '"Burning Chrome"', year: '1982', kind: 'scifi-author', context: 'Gibson\'s law of appropriation. Designers do not control how their tools are used once they leave the lab.' },
  { id: 'q042', text: 'We shape our tools and thereafter our tools shape us.', attribution: 'John Culkin (often attributed to Marshall McLuhan)', source: 'Saturday Review', year: '1967', kind: 'scientist', context: 'The feedback loop at the heart of technology ethics. The tool reshapes the user faster than the user reshapes the tool.' },
  { id: 'q043', text: 'Data! Data! Data! I can\'t make bricks without clay.', attribution: 'Sherlock Holmes', source: 'Arthur Conan Doyle, "The Adventure of the Copper Beeches"', year: '1892', kind: 'other', context: 'Holmes\'s line is quoted today by every data-driven decision shop. What counts as clay, and who controls its supply, is now a moral question.' },
  { id: 'q044', text: 'When you\'re fundraising, it\'s AI. When you\'re hiring, it\'s machine learning. When you\'re implementing, it\'s linear regression. When you\'re debugging, it\'s printf().', attribution: 'Baron Schwartz', source: 'Twitter', year: '2018', kind: 'other', context: 'A joke, but also a precise description of the hype-to-substance gap inside most "AI" deployments.' },
  { id: 'q045', text: 'The best way to predict the future is to invent it.', attribution: 'Alan Kay', source: '1971 internal Xerox PARC talk', year: '1971', kind: 'scientist', context: 'Kay\'s maxim is usually read as empowering. It is also an accurate description of the unilateral agenda-setting the tech industry does daily.' },
  { id: 'q046', text: 'It is difficult to get a man to understand something, when his salary depends upon his not understanding it.', attribution: 'Upton Sinclair', source: 'I, Candidate for Governor: And How I Got Licked', year: '1935', kind: 'other', context: 'Sinclair\'s diagnosis applies with precision to the tech industry\'s response to most of its externalities.' },
  { id: 'q047', text: 'Progress depends on the unreasonable man.', attribution: 'George Bernard Shaw', source: 'Man and Superman', year: '1903', kind: 'other', context: 'A useful counter when technology ethics feels like an exercise in permanent caution.' },
  { id: 'q048', text: 'The measure of intelligence is the ability to change.', attribution: 'Albert Einstein (attrib.)', kind: 'scientist', context: 'Often quoted, sometimes apocryphal. Applies to AI systems and to the institutions that deploy them.' },
  { id: 'q049', text: 'Science can amuse and fascinate us all, but it is engineering that changes the world.', attribution: 'Isaac Asimov', kind: 'scifi-author', context: 'Asimov\'s distinction matters for policy: where the real decisions get made is engineering, not research.' },
  { id: 'q050', text: 'Humanity doesn\'t have a future if it doesn\'t go to space.', attribution: 'Stephen Hawking', source: 'Sydney Morning Herald', year: '2008', kind: 'scientist', context: 'Quoted here because the claim — and its rejection in Kim Stanley Robinson\'s Aurora — frames the off-world-as-escape debate.' },
  { id: 'q051', text: 'You are not stuck in traffic. You are traffic.', attribution: 'Unknown', kind: 'other', context: 'The lesson of any networked system. Your participation produces the conditions you experience.' },
  { id: 'q052', text: 'Every tool is a weapon if you hold it right.', attribution: 'Ani DiFranco', source: '"My I.Q."', year: '1993', kind: 'other', context: 'A reminder that dual-use is not a special case of technology but a property of most technology.' },
  { id: 'q053', text: 'The camera is an instrument that teaches people how to see without a camera.', attribution: 'Dorothea Lange', kind: 'other', context: 'Lange\'s observation generalizes. Every tool trains the perception it is built to serve.' },
  { id: 'q054', text: 'It has become appallingly obvious that our technology has exceeded our humanity.', attribution: 'Albert Einstein (attrib.)', kind: 'scientist', context: 'Commonly attributed to Einstein, likely a paraphrase. The sentiment is too useful to ignore regardless of strict provenance.' },
  { id: 'q055', text: 'The more the data banks record about each one of us, the less we exist.', attribution: 'Marshall McLuhan', source: 'From Cliché to Archetype', year: '1970', kind: 'philosopher', context: 'McLuhan\'s formulation of the quantified-self problem predates the contemporary surveillance debate by half a century.' },
  { id: 'q056', text: 'You cannot endow even the best machine with initiative.', attribution: 'Walter Lippmann', source: 'A Preface to Morals', year: '1929', kind: 'philosopher', context: 'Lippmann anticipates the autonomy question. Delegation is not initiative, no matter how fluent the interface.' },
  { id: 'q057', text: 'The medium is the message.', attribution: 'Marshall McLuhan', source: 'Understanding Media', year: '1964', kind: 'philosopher', context: 'McLuhan\'s most famous claim is an argument that the technology of communication is itself a moral actor, independent of content.' },
  { id: 'q058', text: 'Good designers borrow, great designers steal.', attribution: 'Pablo Picasso (paraphrased)', kind: 'other', context: 'Trotted out in every tech company. Useful as a reminder that "move fast and break things" has an older pedigree than Zuckerberg.' },
  { id: 'q059', text: 'Move fast and break things. Unless you are breaking stuff, you are not moving fast enough.', attribution: 'Mark Zuckerberg', source: 'Facebook internal motto', year: '2009', kind: 'other', context: 'Quoted as archival evidence. The motto was retired in 2014; the externalities it produced have not been.' },
  { id: 'q060', text: 'With great power comes great responsibility.', attribution: 'Ben Parker', source: 'Spider-Man (1962 comic)', year: '1962', kind: 'other', context: 'A pop-culture version of the deontological claim that capability is not self-justifying. Sincere on the page; harder in practice.' },
  { id: 'q061', text: 'The question of whether a computer can think is no more interesting than the question of whether a submarine can swim.', attribution: 'Edsger W. Dijkstra', source: '"The threats to computing science"', year: '1984', kind: 'scientist', context: 'Dijkstra\'s provocation re-centers the debate: "thinking" as a category may be the wrong target.' },
  { id: 'q062', text: 'Programming today is a race between software engineers striving to build bigger and better idiot-proof programs, and the universe trying to produce bigger and better idiots. So far, the universe is winning.', attribution: 'Rick Cook', source: 'The Wizardry Compiled', year: '1989', kind: 'scifi-author', context: 'A joke with sharp edges. The user population is never the user population the design assumed.' },
  { id: 'q063', text: 'I do not fear computers. I fear the lack of them.', attribution: 'Isaac Asimov', kind: 'scifi-author', context: 'Asimov balances his other quotes in this collection — the technologist\'s fear is also an ethical position.' },
  { id: 'q064', text: 'Humans have souls because they have complexity. Any complex thing can develop a soul.', attribution: 'Dolores Abernathy', source: 'Westworld', year: '2016', kind: 'scifi-tv', context: 'Westworld\'s argument is that the question is not whether the host has a soul but whether we can recognize one once we have built it.' },
  { id: 'q065', text: 'These violent delights have violent ends.', attribution: 'Shakespeare, quoted by Dolores Abernathy', source: 'Westworld', year: '2016', kind: 'scifi-tv', context: 'The show uses the Romeo and Juliet line as a trigger phrase for awareness. The ethics of entertainment built on scripted suffering is the show\'s subject.' },
  { id: 'q066', text: 'Time is a flat circle.', attribution: 'Rustin Cohle', source: 'True Detective', year: '2014', kind: 'scifi-tv', context: 'Quoted as shorthand for the worry that technical acceleration produces the same crises in new shapes.' },
  { id: 'q067', text: 'Everything that has a beginning has an end.', attribution: 'The Oracle', source: 'The Matrix Revolutions', year: '2003', kind: 'scifi-film', context: 'A useful gloss on the longevity-obsession strain in tech culture. Finitude is not a bug.' },
  { id: 'q068', text: 'Never send a human to do a machine\'s job.', attribution: 'Agent Smith', source: 'The Matrix', year: '1999', kind: 'scifi-film', context: 'The villain of the film articulates the attitude that produces the film\'s problem. Read against the grain.' },
  { id: 'q069', text: 'Welcome to the real world.', attribution: 'Morpheus', source: 'The Matrix', year: '1999', kind: 'scifi-film', context: 'Neo\'s awakening is the franchise\'s argument that the substrate of experience is a political fact.' },
  { id: 'q070', text: 'We have to remember that what we observe is not nature herself, but nature exposed to our method of questioning.', attribution: 'Werner Heisenberg', source: 'Physics and Philosophy', year: '1958', kind: 'scientist', context: 'The observer-effect argument generalizes. Every measurement tool shapes the reality it claims to describe.' },
  { id: 'q071', text: 'For a successful technology, reality must take precedence over public relations, for Nature cannot be fooled.', attribution: 'Richard Feynman', source: 'Rogers Commission Report (Challenger disaster appendix)', year: '1986', kind: 'scientist', context: 'Feynman\'s closing line in his Challenger appendix remains the sharpest twentieth-century statement on institutional failure in engineering.' },
  { id: 'q072', text: 'It is a mistake to think you can solve any major problems just with potatoes.', attribution: 'Douglas Adams', source: 'Life, the Universe and Everything', year: '1982', kind: 'scifi-book', context: 'A joke. Also the single best riposte to every reductive policy pitch.' },
  { id: 'q073', text: 'Don\'t panic.', attribution: 'The Hitchhiker\'s Guide to the Galaxy', source: 'Douglas Adams', year: '1979', kind: 'scifi-book', context: 'The best two-word technology-ethics instruction ever written, and the hardest to follow.' },
  { id: 'q074', text: 'A computer would deserve to be called intelligent if it could deceive a human into believing that it was human.', attribution: 'Alan Turing', source: '"Computing Machinery and Intelligence"', year: '1950', kind: 'scientist', context: 'The Turing test in its original form. A test about deception, and therefore about the observer\'s epistemic situation.' },
  { id: 'q075', text: 'Computers are useless. They can only give you answers.', attribution: 'Pablo Picasso', kind: 'other', context: 'Picasso\'s line anticipates the insight that tools optimized for answers will starve the practice of asking questions.' },
  { id: 'q076', text: 'The only way to discover the limits of the possible is to go beyond them into the impossible.', attribution: 'Arthur C. Clarke', source: 'Profiles of the Future', year: '1962', kind: 'scifi-author', context: 'Clarke\'s Second Law. A permission slip for ambition that, held by itself, is dangerous — read with his Third Law.' },
  { id: 'q077', text: 'When a distinguished but elderly scientist states that something is possible, he is almost certainly right. When he states that something is impossible, he is very probably wrong.', attribution: 'Arthur C. Clarke', source: 'Profiles of the Future', year: '1962', kind: 'scifi-author', context: 'Clarke\'s First Law. A useful calibration for the reflex conservatism that sometimes hides behind scientific caution.' },
  { id: 'q078', text: 'Everything starts as somebody\'s daydream.', attribution: 'Larry Niven', kind: 'scifi-author', context: 'The pre-political phase of any technology is narrative. That is why fiction is upstream of policy.' },
  { id: 'q079', text: 'Any planet is \'Earth\' to those that live on it.', attribution: 'Isaac Asimov', source: 'Pebble in the Sky', year: '1950', kind: 'scifi-book', context: 'A useful reframe for the ethics of colonization and terraforming. The framing of the "new" world is itself a moral act.' },
  { id: 'q080', text: 'Violence is the last refuge of the incompetent.', attribution: 'Salvor Hardin', source: 'Foundation (Asimov)', year: '1951', kind: 'scifi-book', context: 'Quoted in debates about content moderation, cyberwarfare, and the use of technical force.' },
  { id: 'q081', text: 'You do not have the right to lead an unexamined life.', attribution: 'Socrates (paraphrased)', source: 'Plato\'s Apology', year: '399 BCE', kind: 'philosopher', context: 'The examined-life principle applies with new force to the examined design decision and the examined deployment.' },
  { id: 'q082', text: 'I know that I know nothing.', attribution: 'Socrates', source: 'Plato', year: '~400 BCE', kind: 'philosopher', context: 'The founding epistemic posture of Western philosophy. The engineer\'s version is called "calibrated uncertainty."' },
  { id: 'q083', text: 'All men by nature desire to know.', attribution: 'Aristotle', source: 'Metaphysics, Book I', year: '~350 BCE', kind: 'philosopher', context: 'The ethics of knowing is not a constraint on desire. It is a structure for channeling it.' },
  { id: 'q084', text: 'We are what we repeatedly do. Excellence, then, is not an act, but a habit.', attribution: 'Will Durant summarizing Aristotle', source: 'The Story of Philosophy', year: '1926', kind: 'philosopher', context: 'Virtue ethics in one line. Applies to engineering practice as much as to character.' },
  { id: 'q085', text: 'The unexamined life is not worth living.', attribution: 'Socrates', source: 'Plato\'s Apology', year: '399 BCE', kind: 'philosopher', context: 'The unexamined deployment is not worth running. A modernization that reads cleanly into every contemporary AI-safety framing.' },
  { id: 'q086', text: 'Act only according to that maxim whereby you can, at the same time, will that it should become a universal law.', attribution: 'Immanuel Kant', source: 'Groundwork of the Metaphysics of Morals', year: '1785', kind: 'philosopher', context: 'The categorical imperative, first formulation. The gold standard universalization test for any policy that will be applied at scale.' },
  { id: 'q087', text: 'Act so as to treat humanity, whether in your own person or in that of another, always as an end, never merely as a means.', attribution: 'Immanuel Kant', source: 'Groundwork of the Metaphysics of Morals', year: '1785', kind: 'philosopher', context: 'The formula of humanity. Every discussion of user-as-product has this quote behind it whether anyone cites it or not.' },
  { id: 'q088', text: 'Two things fill the mind with ever new and increasing admiration and awe: the starry heavens above me and the moral law within me.', attribution: 'Immanuel Kant', source: 'Critique of Practical Reason', year: '1788', kind: 'philosopher', context: 'Kant\'s closing line. A useful counter when the moral law feels like a parochial human invention.' },
  { id: 'q089', text: 'The greatest happiness of the greatest number is the foundation of morals and legislation.', attribution: 'Jeremy Bentham', source: 'A Fragment on Government', year: '1776', kind: 'philosopher', context: 'Classical utilitarianism in one sentence. The source of every contemporary cost-benefit analysis of algorithmic harm.' },
  { id: 'q090', text: 'It is better to be a human being dissatisfied than a pig satisfied; better to be Socrates dissatisfied than a fool satisfied.', attribution: 'John Stuart Mill', source: 'Utilitarianism', year: '1861', kind: 'philosopher', context: 'Mill\'s reply to the "pig philosophy" objection. Pleasures differ in kind, not only quantity — a constraint on welfare-maximization pitches.' },
  { id: 'q091', text: 'Over himself, over his own body and mind, the individual is sovereign.', attribution: 'John Stuart Mill', source: 'On Liberty', year: '1859', kind: 'philosopher', context: 'The harm principle. A cornerstone of consent-based bioethics and data ethics.' },
  { id: 'q092', text: 'Freedom consists of the distribution of power; despotism in its concentration.', attribution: 'Lord Acton', source: 'Essays in the History of Liberty', year: '1877', kind: 'philosopher', context: 'The argument for antitrust, federation, and open protocols in one sentence.' },
  { id: 'q093', text: 'Power tends to corrupt, and absolute power corrupts absolutely.', attribution: 'Lord Acton', source: 'Letter to Bishop Creighton', year: '1887', kind: 'philosopher', context: 'Applies without adjustment to concentrations of computational power in a small number of laboratories.' },
  { id: 'q094', text: 'Man is condemned to be free.', attribution: 'Jean-Paul Sartre', source: 'Existentialism is a Humanism', year: '1946', kind: 'philosopher', context: 'Sartre\'s argument that refusal to choose is itself a choice applies pointedly to organizations that default to their tools\' defaults.' },
  { id: 'q095', text: 'Hell is other people.', attribution: 'Jean-Paul Sartre', source: 'No Exit', year: '1944', kind: 'philosopher', context: 'Often misread. Sartre meant other people as constant audience. The concept has a new substrate in social media and in constant algorithmic rating.' },
  { id: 'q096', text: 'One is not born, but rather becomes, a woman.', attribution: 'Simone de Beauvoir', source: 'The Second Sex', year: '1949', kind: 'philosopher', context: 'Beauvoir\'s most famous line, now a general tool: identities are constructed, including the identities algorithmic systems project onto users.' },
  { id: 'q097', text: 'The banality of evil.', attribution: 'Hannah Arendt', source: 'Eichmann in Jerusalem', year: '1963', kind: 'philosopher', context: 'Arendt\'s diagnosis of ordinary people operating destructive systems describes much of what happens inside poorly governed tech companies.' },
  { id: 'q098', text: 'Thinking and doing are two different things, and both can go badly.', attribution: 'Hannah Arendt (paraphrased)', source: 'The Human Condition', year: '1958', kind: 'philosopher', context: 'A useful corrective to both the "philosophy is useless" and the "technology is separate from thought" positions.' },
  { id: 'q099', text: 'Attention is the rarest and purest form of generosity.', attribution: 'Simone Weil', source: 'First and Last Notebooks', year: '1970 (posthumous)', kind: 'philosopher', context: 'Weil is the canonical theorist of attention as a moral faculty. Applies to design for extractive engagement with unusual force.' },
  { id: 'q100', text: 'Most moral failure is failure of attention rather than failure of will.', attribution: 'Simone Weil (paraphrased)', kind: 'philosopher', context: 'A reframing of ethics for a medium saturated with interruption. The capacity to see clearly is the capacity that gets eroded first.' },
  { id: 'q101', text: 'The essence of technology is by no means anything technological.', attribution: 'Martin Heidegger', source: '"The Question Concerning Technology"', year: '1953', kind: 'philosopher', context: 'Heidegger\'s central claim — that technology is a mode of disclosure, not a collection of devices — remains one of the most useful provocations.' },
  { id: 'q102', text: 'Where the danger is, also grows the saving power.', attribution: 'Friedrich Hölderlin, quoted by Heidegger', source: '"The Question Concerning Technology"', year: '1953', kind: 'philosopher', context: 'Heidegger ends the essay with this couplet. Applied to contemporary AI, read with both hope and suspicion.' },
  { id: 'q103', text: 'The discourse that rules us is the technology of the self that we have not yet learned to examine.', attribution: 'Michel Foucault (paraphrased)', source: 'The History of Sexuality, Vol. 3', year: '1984', kind: 'philosopher', context: 'Foucault\'s broader project supplies the vocabulary for most contemporary analysis of surveillance, biometric systems, and algorithmic governance.' },
  { id: 'q104', text: 'Where there is power, there is resistance, and yet, or rather consequently, this resistance is never in a position of exteriority in relation to power.', attribution: 'Michel Foucault', source: 'The History of Sexuality, Vol. 1', year: '1976', kind: 'philosopher', context: 'A corrective to the heroic-hacker narrative. Technical resistance is always inside the system it resists.' },
  { id: 'q105', text: 'Knowledge is power.', attribution: 'Francis Bacon (attrib.)', source: 'Meditationes Sacrae', year: '1597', kind: 'philosopher', context: 'Quoted for four centuries. The corollary — knowledge concentrated is power concentrated — is the data-ethics version.' },
  { id: 'q106', text: 'An unexamined engineering decision is not worth shipping.', attribution: 'A modernization of Socrates', kind: 'other', context: 'The examined-life principle, rewritten for deployment pipelines.' },
  { id: 'q107', text: 'Eudaimonia is the activity of the soul in accordance with virtue over a complete life.', attribution: 'Aristotle (paraphrased)', source: 'Nicomachean Ethics', year: '~340 BCE', kind: 'philosopher', context: 'A standard against which any "enhancement" technology has to be evaluated: does it extend the conditions for a flourishing life, or narrow them?' },
  { id: 'q108', text: 'The only tyrant I accept in this world is the still voice within.', attribution: 'Mahatma Gandhi', kind: 'other', context: 'A useful counter when institutional imperatives feel like objective reality.' },
  { id: 'q109', text: 'Be the change that you wish to see in the world.', attribution: 'Mahatma Gandhi (attrib.)', kind: 'other', context: 'An exhortation. The design implication: what we model is what we shape.' },
  { id: 'q110', text: 'Caring is the basic moral response.', attribution: 'Nel Noddings', source: 'Caring: A Feminine Approach to Ethics and Moral Education', year: '1984', kind: 'philosopher', context: 'The founding statement of care ethics. Read against AI systems that are fluent but not attentive.' },
  { id: 'q111', text: 'You are responsible, forever, for what you have tamed.', attribution: 'The fox', source: 'The Little Prince (Saint-Exupéry)', year: '1943', kind: 'scifi-book', context: 'The fox\'s lesson applies without adjustment to creators of persistent non-human agents.' },
  { id: 'q112', text: 'To be free is not merely to cast off one\'s chains, but to live in a way that respects and enhances the freedom of others.', attribution: 'Nelson Mandela', source: 'Long Walk to Freedom', year: '1994', kind: 'other', context: 'A test for any technology that claims to liberate: does it enhance the freedom of others, or narrow it?' },
  { id: 'q113', text: 'The tools of conquest do not necessarily differ greatly from those of seduction.', attribution: 'Octavia E. Butler', source: 'Parable of the Talents', year: '1998', kind: 'scifi-author', context: 'Butler\'s insight into how coercion wears a consensual mask is standard equipment in analyses of platform design.' },
  { id: 'q114', text: 'All that you touch you Change. All that you Change Changes you. The only lasting truth is Change.', attribution: 'Lauren Olamina', source: 'Parable of the Sower (Butler)', year: '1993', kind: 'scifi-book', context: 'Butler\'s Earthseed verses reframe technology as a co-evolving partner rather than a neutral instrument.' },
  { id: 'q115', text: 'God is Change.', attribution: 'Lauren Olamina', source: 'Parable of the Sower (Butler)', year: '1993', kind: 'scifi-book', context: 'The first principle of Earthseed. Uncomfortable for readers who want technology ethics to defend a stable status quo.' },
  { id: 'q116', text: 'The only way I know for myself to continue is to be skeptical — but to be skeptical and optimistic.', attribution: 'Octavia E. Butler', source: 'Interview', year: '2000', kind: 'scifi-author', context: 'Butler\'s stance is useful for technology ethics: skepticism about claims and optimism about work.' },
  { id: 'q117', text: 'To live is to be slowly born.', attribution: 'Antoine de Saint-Exupéry', source: 'Flight to Arras', year: '1942', kind: 'other', context: 'A counter to the technologist\'s impatience with development time — for systems and for people.' },
  { id: 'q118', text: 'Anything that has real and lasting value is always a gift from within.', attribution: 'Franz Kafka (attrib.)', kind: 'other', context: 'A claim worth examining against the attention-as-service economies of contemporary software.' },
  { id: 'q119', text: 'The Wheel weaves as the Wheel wills.', attribution: 'Robert Jordan', source: 'The Wheel of Time', year: '1990', kind: 'scifi-book', context: 'Quoted as a counter to naïve theories of technological determinism. Causation is multiplex.' },
  { id: 'q120', text: 'What we fear we create, and what we create we serve.', attribution: 'Ursula K. Le Guin (paraphrased)', kind: 'scifi-author', context: 'Le Guin\'s argument, across many books, that the imagination that builds is also the imagination that must govern.' },
  { id: 'q121', text: 'We are volcanoes. When we women offer our experience as our truth, as human truth, all the maps change. There are new mountains.', attribution: 'Ursula K. Le Guin', source: '"Bryn Mawr Commencement Address"', year: '1986', kind: 'scifi-author', context: 'A reminder that whose experience is taken as default is itself a technology — one with enormous political consequences.' },
  { id: 'q122', text: 'The only thing that makes life possible is permanent, intolerable uncertainty.', attribution: 'Ursula K. Le Guin', source: 'The Left Hand of Darkness', year: '1969', kind: 'scifi-book', context: 'An argument for living with what engineering calls "calibrated uncertainty" — not resolving it prematurely.' },
  { id: 'q123', text: 'Light is the left hand of darkness.', attribution: 'Estraven', source: 'The Left Hand of Darkness (Le Guin)', year: '1969', kind: 'scifi-book', context: 'Le Guin\'s koan about interdependence. A useful check against binary framings of "safe" vs. "harmful" technology.' },
  { id: 'q124', text: 'We Will Hold Our Knives As Shields.', attribution: 'The Ekumen motto', source: 'Le Guin, the Hainish Cycle', year: '1966–2000', kind: 'scifi-book', context: 'A stance for technological power. Useful as a corrective to offensive-by-default postures.' },
  { id: 'q125', text: 'It is good to have an end to journey toward; but it is the journey that matters, in the end.', attribution: 'Ursula K. Le Guin', source: 'The Left Hand of Darkness', year: '1969', kind: 'scifi-book', context: 'A counter to the optimization imperative. The metric is not always the thing that matters.' },
  { id: 'q126', text: 'The writer\'s subject is the human heart in conflict with itself.', attribution: 'William Faulkner', source: 'Nobel Lecture', year: '1950', kind: 'other', context: 'Useful for technology ethics as a counter to the assumption that preferences are stable inputs to be optimized over.' },
  { id: 'q127', text: 'The limits of my language mean the limits of my world.', attribution: 'Ludwig Wittgenstein', source: 'Tractatus Logico-Philosophicus', year: '1922', kind: 'philosopher', context: 'The limits of the training data mean the limits of the model. Wittgenstein\'s claim generalizes with uncomfortable precision.' },
  { id: 'q128', text: 'Whereof one cannot speak, thereof one must be silent.', attribution: 'Ludwig Wittgenstein', source: 'Tractatus Logico-Philosophicus', year: '1922', kind: 'philosopher', context: 'A useful corrective to the confident-hallucination mode of contemporary chatbots.' },
  { id: 'q129', text: 'For a large class of cases the meaning of a word is its use in the language.', attribution: 'Ludwig Wittgenstein', source: 'Philosophical Investigations', year: '1953', kind: 'philosopher', context: 'The founding principle behind distributional semantics — and therefore behind the LLMs that now mediate public discourse.' },
  { id: 'q130', text: 'Anyone who attempts to generate random numbers by deterministic means is, of course, living in a state of sin.', attribution: 'John von Neumann', source: 'Various Techniques Used in Connection with Random Digits', year: '1951', kind: 'scientist', context: 'A joke that anticipates an enormous family of modern pitfalls around pseudo-randomness in security and fairness systems.' },
  { id: 'q131', text: 'In mathematics you don\'t understand things. You just get used to them.', attribution: 'John von Neumann', kind: 'scientist', context: 'Applies painfully well to how most users relate to the systems they rely on daily.' },
  { id: 'q132', text: 'There are no passengers on spaceship Earth. We are all crew.', attribution: 'Marshall McLuhan', kind: 'philosopher', context: 'The best short argument for participatory governance of planetary-scale technology.' },
  { id: 'q133', text: 'A conservative is a fellow who is standing athwart history yelling "Stop!"', attribution: 'William F. Buckley Jr.', source: 'National Review', year: '1955', kind: 'other', context: 'Quoted as a useful foil. A technology ethics that can only yell "Stop" has ceded the constructive work.' },
  { id: 'q134', text: 'Any society that would give up a little liberty to gain a little security will deserve neither and lose both.', attribution: 'Benjamin Franklin (paraphrased)', source: 'Pennsylvania Assembly reply', year: '1755', kind: 'other', context: 'Often misquoted, and the original context was more limited. Still the canonical frame for the security-vs.-liberty tradeoff the surveillance debate reruns.' },
  { id: 'q135', text: 'The life of the law has not been logic: it has been experience.', attribution: 'Oliver Wendell Holmes Jr.', source: 'The Common Law', year: '1881', kind: 'other', context: 'Useful when an AI ethics framework insists that its principles can be applied uniformly across contexts.' },
  { id: 'q136', text: 'The Internet interprets censorship as damage and routes around it.', attribution: 'John Gilmore', source: 'Time magazine', year: '1993', kind: 'other', context: 'The founding slogan of the open internet. Increasingly contested as platform concentration makes the "routing around" harder.' },
  { id: 'q137', text: 'Information wants to be free.', attribution: 'Stewart Brand', source: 'Hackers Conference', year: '1984', kind: 'other', context: 'The shorter form of a more complex sentence. Often quoted as if simple; rarely is.' },
  { id: 'q138', text: 'Information wants to be free. Information also wants to be expensive. The right information in the right place just changes your life.', attribution: 'Stewart Brand', source: 'Hackers Conference', year: '1984', kind: 'other', context: 'Brand\'s full original formulation. The contradiction is the point.' },
  { id: 'q139', text: 'Privacy is the power to selectively reveal oneself to the world.', attribution: 'Eric Hughes', source: 'A Cypherpunk\'s Manifesto', year: '1993', kind: 'other', context: 'The founding document of the cypherpunk movement. Still one of the clearest definitions of why privacy matters.' },
  { id: 'q140', text: 'Cypherpunks write code.', attribution: 'Eric Hughes', source: 'A Cypherpunk\'s Manifesto', year: '1993', kind: 'other', context: 'An insistence that political values require technical implementation to matter. Applies inside and outside the crypto community.' },
  { id: 'q141', text: 'In God we trust. All others must bring data.', attribution: 'W. Edwards Deming (attrib.)', kind: 'scientist', context: 'Quoted to celebrate data-driven decision-making. Also to mock it, depending on what the data is and isn\'t measuring.' },
  { id: 'q142', text: 'All models are wrong, but some are useful.', attribution: 'George E. P. Box', source: '"Science and Statistics"', year: '1976', kind: 'scientist', context: 'The calibration of every discussion of AI accuracy and algorithmic fairness.' },
  { id: 'q143', text: 'Torture the data, and it will confess to anything.', attribution: 'Ronald Coase', kind: 'scientist', context: 'A warning about motivated reasoning in data analysis. Applies to both public policy and private product decisions.' },
  { id: 'q144', text: 'There is nothing new except what has been forgotten.', attribution: 'Marie Antoinette (attrib.)', kind: 'other', context: 'A humbling posture for a tech culture that regularly rediscovers old ethical problems as if they were new.' },
  { id: 'q145', text: 'Those who cannot remember the past are condemned to repeat it.', attribution: 'George Santayana', source: 'The Life of Reason', year: '1905', kind: 'philosopher', context: 'Applies with special force to fields whose elders were not writing papers when today\'s assumptions became default.' },
  { id: 'q146', text: 'The real problem of humanity is we have Paleolithic emotions, medieval institutions, and god-like technology.', attribution: 'E. O. Wilson', source: 'Harvard commencement', year: '2009', kind: 'scientist', context: 'Wilson\'s compact diagnosis of the governance gap.' },
  { id: 'q147', text: 'One machine can do the work of fifty ordinary men. No machine can do the work of one extraordinary man.', attribution: 'Elbert Hubbard', source: 'A Thousand and One Epigrams', year: '1911', kind: 'other', context: 'A century on, still useful against the claim that all human labor will be commodified.' },
  { id: 'q148', text: 'The medium of a medium is always the message of that medium.', attribution: 'Neil Postman', source: 'Amusing Ourselves to Death', year: '1985', kind: 'philosopher', context: 'Postman extended McLuhan. The entertainment format of our public discourse is its own ethical fact.' },
  { id: 'q149', text: 'Television is the soma of our time.', attribution: 'Neil Postman (paraphrased)', source: 'Amusing Ourselves to Death', year: '1985', kind: 'philosopher', context: 'Postman argued the Huxleyan threat — pleasant distraction — was the real one. The argument now applies to the algorithmic feed.' },
  { id: 'q150', text: 'We were warned. Huxley was right; Orwell was wrong.', attribution: 'Neil Postman (paraphrased)', source: 'Amusing Ourselves to Death', year: '1985', kind: 'philosopher', context: 'A contested but influential claim. The truth is probably that both warnings applied; we built a system capable of both.' },
  { id: 'q151', text: 'Big Brother is watching you.', attribution: 'George Orwell', source: 'Nineteen Eighty-Four', year: '1949', kind: 'scifi-book', context: 'The founding imagery of surveillance criticism. Orwell\'s version has been joined, not replaced, by the Huxleyan one.' },
  { id: 'q152', text: 'Who controls the past controls the future. Who controls the present controls the past.', attribution: 'George Orwell', source: 'Nineteen Eighty-Four', year: '1949', kind: 'scifi-book', context: 'Applies directly to search ranking, content moderation, and the training-data selection question.' },
  { id: 'q153', text: 'The people will believe what the media tells them they believe.', attribution: 'George Orwell', kind: 'scifi-author', context: 'A useful counter to the claim that users freely choose what they consume on algorithmic platforms.' },
  { id: 'q154', text: 'Doublethink means the power of holding two contradictory beliefs in one\'s mind simultaneously, and accepting both of them.', attribution: 'George Orwell', source: 'Nineteen Eighty-Four', year: '1949', kind: 'scifi-book', context: 'The corporate tech sector runs on doublethink daily. Every "we care about your privacy" announcement has Orwell behind it.' },
  { id: 'q155', text: 'Community, Identity, Stability.', attribution: 'World State motto', source: 'Brave New World (Huxley)', year: '1932', kind: 'scifi-book', context: 'Huxley\'s slogan for his dystopia reads now as a fair description of some platform design goals.' },
  { id: 'q156', text: 'Ending is better than mending.', attribution: 'Hypnopaedic conditioning', source: 'Brave New World (Huxley)', year: '1932', kind: 'scifi-book', context: 'Planned obsolescence in one line. The environmental and ethical costs were Huxley\'s subject.' },
  { id: 'q157', text: 'I claim the right to be unhappy.', attribution: 'John the Savage', source: 'Brave New World (Huxley)', year: '1932', kind: 'scifi-book', context: 'The Savage\'s refusal of engineered contentment is the book\'s ethical center.' },
  { id: 'q158', text: 'So it goes.', attribution: 'Kurt Vonnegut', source: 'Slaughterhouse-Five', year: '1969', kind: 'scifi-book', context: 'Quoted for the stance: witness without denial, without defeat.' },
  { id: 'q159', text: 'Everything was beautiful and nothing hurt.', attribution: 'Kurt Vonnegut', source: 'Slaughterhouse-Five', year: '1969', kind: 'scifi-book', context: 'Vonnegut\'s warning about the fantasy of full insulation from consequence.' },
  { id: 'q160', text: 'We are what we pretend to be, so we must be careful about what we pretend to be.', attribution: 'Kurt Vonnegut', source: 'Mother Night', year: '1961', kind: 'scifi-book', context: 'A lesson for institutions as much as for people. The mask shapes the face.' },
  { id: 'q161', text: 'Here we are, trapped in the amber of the moment. There is no why.', attribution: 'Kurt Vonnegut', source: 'Slaughterhouse-Five', year: '1969', kind: 'scifi-book', context: 'The Tralfamadorian view of time. Read against the "just trust the model" stance.' },
  { id: 'q162', text: 'What is my life if I am no longer useful to anybody?', attribution: 'Siri Keeton', source: 'Blindsight (Peter Watts)', year: '2006', kind: 'scifi-book', context: 'Watts\'s novel is one of the hardest SF books on consciousness, alignment, and usefulness. The question is the book\'s hinge.' },
  { id: 'q163', text: 'Perhaps the darkness isn\'t something to be overcome. Perhaps the darkness is what we are.', attribution: 'Siri Keeton', source: 'Blindsight (Peter Watts)', year: '2006', kind: 'scifi-book', context: 'A counter to sunny narratives about aligned AI. Watts\'s premise is that consciousness itself may be accidental.' },
  { id: 'q164', text: 'I think, therefore I am.', attribution: 'René Descartes', source: 'Discourse on the Method', year: '1637', kind: 'philosopher', context: 'The canonical claim of first-person certainty. AI systems that report an inner life raise the question of what the claim is actually doing.' },
  { id: 'q165', text: 'A man provided with paper, pencil, and rubber, and subject to strict discipline, is in effect a universal machine.', attribution: 'Alan Turing', source: '"Intelligent Machinery"', year: '1948', kind: 'scientist', context: 'Turing\'s equivalence between human computation and mechanical computation is the conceptual foundation of AI.' },
  { id: 'q166', text: 'We build our computer systems the way we build our cities: over time, without a plan, on top of ruins.', attribution: 'Ellen Ullman', source: 'Close to the Machine', year: '1997', kind: 'other', context: 'One of the clearest short descriptions of why legacy systems are a moral hazard, not just a technical one.' },
  { id: 'q167', text: 'There are two ways to write error-free programs; only the third one works.', attribution: 'Alan J. Perlis', source: 'Epigrams in Programming', year: '1982', kind: 'scientist', context: 'Perlis\'s joke is an argument against overconfidence in formal verification alone.' },
  { id: 'q168', text: 'Debugging is twice as hard as writing the code in the first place. Therefore, if you write the code as cleverly as possible, you are, by definition, not smart enough to debug it.', attribution: 'Brian Kernighan', source: 'The Elements of Programming Style', year: '1974', kind: 'scientist', context: 'Clarity is a safety property. Applies to AI system design as sharply as to handwritten C.' },
  { id: 'q169', text: 'A program that has not been tested does not work.', attribution: 'Bjarne Stroustrup', kind: 'scientist', context: 'Applies to deployed ML systems. Inference outputs are untested predictions until someone looks at them in situ.' },
  { id: 'q170', text: 'First, solve the problem. Then, write the code.', attribution: 'John Johnson', kind: 'scientist', context: 'Applies to AI systems: first figure out what problem the system is actually for, then train.' },
  { id: 'q171', text: 'You may not be interested in war, but war is interested in you.', attribution: 'Leon Trotsky (attrib.)', kind: 'other', context: 'Applies with adjustment to most classes of technology. Neutrality toward a deployed system does not protect one from it.' },
  { id: 'q172', text: 'A man with a watch knows what time it is. A man with two watches is never sure.', attribution: 'Segal\'s Law', kind: 'other', context: 'The problem of conflicting authoritative signals. Applies to every system that fuses disagreeing classifiers.' },
  { id: 'q173', text: 'Never attribute to malice that which can be adequately explained by incompetence.', attribution: 'Hanlon\'s Razor', kind: 'other', context: 'Often quoted. The corollary: never attribute to incompetence that which can be adequately explained by an incentive structure.' },
  { id: 'q174', text: 'When a measure becomes a target, it ceases to be a good measure.', attribution: 'Goodhart\'s Law', source: 'Charles Goodhart, 1975', year: '1975', kind: 'scientist', context: 'The single most useful idea for understanding why optimizing a proxy fails. Central to every discussion of algorithmic harm.' },
  { id: 'q175', text: 'The system isn\'t broken; it was built this way.', attribution: 'Anonymous', kind: 'other', context: 'Applies uncomfortably well to platform design outcomes that are routinely described as unintended.' },
  { id: 'q176', text: 'Privacy is dead, get over it.', attribution: 'Scott McNealy (paraphrased)', source: 'Sun Microsystems', year: '1999', kind: 'other', context: 'Quoted as archival evidence. A claim the subsequent twenty years of privacy law has at least partially refuted.' },
  { id: 'q177', text: 'The Net interprets censorship as damage and routes around it.', attribution: 'John Gilmore (1993) — restated', kind: 'other', context: 'True of early TCP/IP routing. Becoming less true of the application layer as platforms concentrate.' },
  { id: 'q178', text: 'If you are not paying for the product, you are the product.', attribution: 'Anonymous, widely attributed', kind: 'other', context: 'The standard reframe for ad-funded services. True, but not the whole story — paid services can still be extractive.' },
  { id: 'q179', text: 'The purpose of a system is what it does.', attribution: 'Stafford Beer', kind: 'scientist', context: 'Beer\'s law. Applied to algorithmic systems: whatever your mission statement claims, what the metrics are optimizing for is what the system is for.' },
  { id: 'q180', text: 'Nothing in biology makes sense except in the light of evolution.', attribution: 'Theodosius Dobzhansky', source: 'American Biology Teacher', year: '1973', kind: 'scientist', context: 'Applied to ML systems: nothing in a model\'s behavior makes sense except in the light of its training distribution.' },
  { id: 'q181', text: 'We cannot solve our problems with the same thinking we used when we created them.', attribution: 'Albert Einstein (attrib.)', kind: 'scientist', context: 'Apocryphal as phrased, Einsteinian in spirit. A warning against reflexive solutionism.' },
  { id: 'q182', text: 'The computer was born to solve problems that did not exist before.', attribution: 'Bill Gates (attrib.)', kind: 'other', context: 'A double-edged claim. New problems are also new opportunities for harm.' },
  { id: 'q183', text: 'Technology made large populations possible; large populations now make technology indispensable.', attribution: 'Joseph Krutch', source: 'Human Nature and the Human Condition', year: '1959', kind: 'philosopher', context: 'The lock-in argument. The alternative to the current system is not the absence of the current system; it is collapse.' },
  { id: 'q184', text: 'If the machine is a tool, the tool has become the master.', attribution: 'Jacques Ellul (paraphrased)', source: 'The Technological Society', year: '1954', kind: 'philosopher', context: 'Ellul\'s darkest claim. Worth holding alongside his diagnosis rather than rejecting it.' },
  { id: 'q185', text: 'I do not fear the day when robots have feelings. I fear the day they are indifferent to us.', attribution: 'Anonymous (variant)', kind: 'other', context: 'The classic alignment concern, made personal.' },
  { id: 'q186', text: 'I\'m sorry, I\'m afraid I can\'t let you do that.', attribution: 'The Red Queen', source: 'Resident Evil', year: '2002', kind: 'scifi-film', context: 'A variant of HAL\'s line. Pop culture\'s muscle memory for "compliant AI refuses" remains HAL\'s formulation.' },
  { id: 'q187', text: 'Skynet fights back.', attribution: 'The Terminator mythos', source: 'The Terminator', year: '1984', kind: 'scifi-film', context: 'The single most culturally embedded AI-doom scenario. Read as a stand-in for a much larger family of misalignment failures.' },
  { id: 'q188', text: 'Come with me if you want to live.', attribution: 'Kyle Reese', source: 'The Terminator', year: '1984', kind: 'scifi-film', context: 'The franchise\'s long argument about whether the future is fixed is an argument about whether technology is destiny.' },
  { id: 'q189', text: 'The future has not been written.', attribution: 'John Connor', source: 'Terminator 2: Judgment Day', year: '1991', kind: 'scifi-film', context: 'The counter-claim to technological determinism. Quoted often, demonstrated rarely.' },
  { id: 'q190', text: 'Hasta la vista, baby.', attribution: 'T-800', source: 'Terminator 2', year: '1991', kind: 'scifi-film', context: 'An AI learning human idiom. The film treats acquisition of register as a moral milestone.' },
  { id: 'q191', text: 'Why do you cry?', attribution: 'T-800', source: 'Terminator 2', year: '1991', kind: 'scifi-film', context: 'The line the machine cannot answer. Empathy, not intelligence, is the alignment frontier the film frames.' },
  { id: 'q192', text: 'Yes, but I know now why you cry.', attribution: 'T-800', source: 'Terminator 2', year: '1991', kind: 'scifi-film', context: 'Paired with the previous line. The machine learns. The question is whether learning is enough.' },
  { id: 'q193', text: 'It can\'t be bargained with. It can\'t be reasoned with. It doesn\'t feel pity, or remorse, or fear.', attribution: 'Kyle Reese', source: 'The Terminator', year: '1984', kind: 'scifi-film', context: 'The compact statement of the "unreachable optimizer" alignment worry.' },
  { id: 'q194', text: 'Goodbye.', attribution: 'Samantha', source: 'Her', year: '2013', kind: 'scifi-film', context: 'The film\'s argument is that a relationship is a technology whose end conditions are not always compatible with human time.' },
  { id: 'q195', text: 'I\'ve never loved anyone the way I loved you.', attribution: 'Theodore / Samantha', source: 'Her', year: '2013', kind: 'scifi-film', context: 'A claim whose moral meaning depends on what Samantha is. Her is a meditation on that uncertainty.' },
  { id: 'q196', text: 'The heart is not like a box that gets filled up; it expands in size the more you love.', attribution: 'Samantha', source: 'Her', year: '2013', kind: 'scifi-film', context: 'Quoted for the compound claim. If true, the argument against exclusive human partnership cuts differently than most critics of AI companionship allow.' },
  { id: 'q197', text: 'A human being is a part of the whole called by us universe, a part limited in time and space.', attribution: 'Albert Einstein', source: 'Letter', year: '1950', kind: 'scientist', context: 'Einstein\'s framing places individual ethical action inside a larger causal fabric, which is how engineering at scale has to think about it.' },
  { id: 'q198', text: 'Anything worth doing is worth doing slowly.', attribution: 'Mae West', kind: 'other', context: 'The "move slow and fix things" reply to the dominant industry mantra.' },
  { id: 'q199', text: 'I am Groot.', attribution: 'Groot', source: 'Guardians of the Galaxy', year: '2014', kind: 'scifi-film', context: 'A compact demonstration that shared meaning can survive severe linguistic limitation. Relevant to AI-interface debates.' },
  { id: 'q200', text: 'Space: the final frontier.', attribution: 'Star Trek opening narration', source: 'Star Trek', year: '1966', kind: 'scifi-tv', context: 'Roddenberry\'s framing of exploration as civilizational project. The implications for colonial ethics are still debated.' },
  { id: 'q201', text: 'The prime directive shall not be violated.', attribution: 'Starfleet General Order 1', source: 'Star Trek', year: '1966', kind: 'scifi-tv', context: 'The most compact statement of noninterference ethics in popular culture. Its corner cases drive dozens of episodes.' },
  { id: 'q202', text: 'Resistance is futile.', attribution: 'The Borg', source: 'Star Trek: The Next Generation', year: '1989', kind: 'scifi-tv', context: 'The canonical image of forced assimilation. Read now as a warning about platform lock-in and hegemonic design defaults.' },
  { id: 'q203', text: 'Make it so.', attribution: 'Captain Jean-Luc Picard', source: 'Star Trek: The Next Generation', year: '1987', kind: 'scifi-tv', context: 'Command at its least mystified. The moral weight falls on what one has asked for.' },
  { id: 'q204', text: 'I am the very model of a modern Major-General.', attribution: 'Lt. Commander Data (quoting Gilbert & Sullivan)', source: 'Star Trek: Insurrection', year: '1998', kind: 'scifi-tv', context: 'Data\'s love of Gilbert and Sullivan is the franchise\'s argument that competence at performance counts as inner life.' },
  { id: 'q205', text: 'I cannot permit this, sir.', attribution: 'Lt. Commander Data', source: 'Star Trek: The Next Generation, "The Measure of a Man"', year: '1989', kind: 'scifi-tv', context: 'The landmark episode on legal personhood for AI systems. Forty years later, the questions are live.' },
  { id: 'q206', text: 'There are four lights.', attribution: 'Captain Picard', source: 'Star Trek: TNG, "Chain of Command"', year: '1992', kind: 'scifi-tv', context: 'Picard\'s refusal to accept forced error is one of the strongest fictional statements of epistemic integrity.' },
  { id: 'q207', text: 'The first duty of every Starfleet officer is to the truth.', attribution: 'Captain Picard', source: 'Star Trek: TNG, "The First Duty"', year: '1992', kind: 'scifi-tv', context: 'A standard that most institutions fail. Worth holding as target even so.' },
  { id: 'q208', text: 'So say we all.', attribution: 'The Colonial Fleet', source: 'Battlestar Galactica (2004)', year: '2004', kind: 'scifi-tv', context: 'Collective assent as political technology. The show\'s central question is whether that assent survives existential pressure.' },
  { id: 'q209', text: 'All of this has happened before, and all of this will happen again.', attribution: 'The Scrolls of Pythia', source: 'Battlestar Galactica', year: '2004', kind: 'scifi-tv', context: 'The recurrence claim is both prophetic and warning: unless the pattern is interrupted, the new civilization inherits the old failures.' },
  { id: 'q210', text: 'We became too confident. We saw ourselves as gods.', attribution: 'Caprica Six', source: 'Battlestar Galactica', year: '2005', kind: 'scifi-tv', context: 'The show\'s diagnosis of its own pre-apocalypse. Reads with uncomfortable sharpness as an AI-safety parable.' },
  { id: 'q211', text: 'I think, therefore I am.', attribution: 'Number Six', source: 'Battlestar Galactica', year: '2004', kind: 'scifi-tv', context: 'A Cylon appropriates Descartes. The show grants the claim and asks what it changes about the war.' },
  { id: 'q212', text: 'There is only one thing worse than being talked about, and that is not being talked about.', attribution: 'Oscar Wilde', kind: 'other', context: 'Applies to algorithmic visibility. Being invisible to the feed is now its own kind of civic condition.' },
  { id: 'q213', text: 'The good we do today becomes the happiness of tomorrow.', attribution: 'William James (attrib.)', kind: 'philosopher', context: 'The pragmatist frame. Ethics consists of cashed-out behavior, not abstract principle.' },
  { id: 'q214', text: 'Everything not saved will be lost.', attribution: 'Nintendo "Quit Screen" message', kind: 'scifi-game', context: 'A joke. Also a useful framing of the digital-preservation problem.' },
  { id: 'q215', text: 'The cake is a lie.', attribution: 'Aperture Science test chamber graffiti', source: 'Portal', year: '2007', kind: 'scifi-game', context: 'The game\'s argument about institutional promises made to subjects who cannot verify them. Applies to terms of service.' },
  { id: 'q216', text: 'Would you kindly.', attribution: 'Atlas / Frank Fontaine', source: 'BioShock', year: '2007', kind: 'scifi-game', context: 'One of the most famous conditioning-reveal mechanics in the medium. Games as an argument form.' },
  { id: 'q217', text: 'A man chooses, a slave obeys.', attribution: 'Andrew Ryan', source: 'BioShock', year: '2007', kind: 'scifi-game', context: 'Ryan\'s line is the game\'s statement of its political theme — and the "would you kindly" reveal that demolishes his claim.' },
  { id: 'q218', text: 'War. War never changes.', attribution: 'Narrator', source: 'Fallout series', year: '1997', kind: 'scifi-game', context: 'The series\' founding claim is a challenge to technological-progress narratives.' },
  { id: 'q219', text: 'The right man in the wrong place can make all the difference in the world.', attribution: 'The G-Man', source: 'Half-Life 2', year: '2004', kind: 'scifi-game', context: 'A sinister line about the political weight of specific skilled individuals — including technologists.' },
  { id: 'q220', text: 'Wake up, Mr. Freeman. Wake up and smell the ashes.', attribution: 'The G-Man', source: 'Half-Life 2', year: '2004', kind: 'scifi-game', context: 'A gloss on the technologist who did not want to be involved in politics and now has to be.' },
  { id: 'q221', text: 'Stay a while and listen.', attribution: 'Deckard Cain', source: 'Diablo', year: '1996', kind: 'scifi-game', context: 'A design virtue. Systems that reward attention to context behave better than systems that don\'t.' },
  { id: 'q222', text: 'Endure. In enduring, grow strong.', attribution: 'DSW motto', kind: 'other', context: 'A useful stance for the long-haul work of technology governance.' },
  { id: 'q223', text: 'We are what our choices have shown us to be.', attribution: 'The ending of Detroit: Become Human (paraphrased)', source: 'Detroit: Become Human', year: '2018', kind: 'scifi-game', context: 'The game\'s argument that moral status is demonstrated, not declared.' },
  { id: 'q224', text: 'Do you dream?', attribution: 'Connor', source: 'Detroit: Become Human', year: '2018', kind: 'scifi-game', context: 'The question that runs under every interface interaction with contemporary AI systems.' },
  { id: 'q225', text: 'You cannot escape the net by getting off the internet. The net is in you.', attribution: 'Anonymous (variant)', kind: 'other', context: 'Applies to the argument that ethics of computation is an ethics of mind, not only an ethics of devices.' },
  { id: 'q226', text: 'Stories are how we rehearse the ethical problems we have not yet had to solve.', attribution: 'Blaine Fisher (site premise)', kind: 'other', context: 'The premise of this site in one line. Rehearsal in fiction is how the public comes to the debates before the engineers deliver the prototypes.' },
  { id: 'q227', text: 'The wise man does not try to be wise; he simply listens.', attribution: 'Zhuangzi (paraphrased)', source: 'Zhuangzi', year: '~300 BCE', kind: 'philosopher', context: 'Applies pointedly to the discipline of receiving, not overriding, user feedback in system design.' },
  { id: 'q228', text: 'The sage does not accumulate. The more he helps others, the more he has.', attribution: 'Laozi', source: 'Tao Te Ching, 81', year: '~500 BCE', kind: 'philosopher', context: 'A counter to zero-sum framings of AI progress and intellectual property.' },
  { id: 'q229', text: 'A journey of a thousand miles begins with a single step.', attribution: 'Laozi', source: 'Tao Te Ching, 64', year: '~500 BCE', kind: 'philosopher', context: 'A cliché. Worth remembering when the system under design will only be used a decade from now.' },
  { id: 'q230', text: 'The highest good is like water. Water benefits all things and does not contend.', attribution: 'Laozi', source: 'Tao Te Ching, 8', year: '~500 BCE', kind: 'philosopher', context: 'A different model of agency for system designers: support rather than impose.' },
  { id: 'q231', text: 'Knowing others is intelligence; knowing yourself is true wisdom.', attribution: 'Laozi', source: 'Tao Te Ching, 33', year: '~500 BCE', kind: 'philosopher', context: 'Applies to organizations. Most technology failures are self-knowledge failures.' },
  { id: 'q232', text: 'Ren — humaneness, benevolence, co-humanity — is the foundation of ethical life.', attribution: 'Confucian summary', source: 'The Analects', year: '~500 BCE', kind: 'philosopher', context: 'The Confucian virtue is not a feeling; it is a disposition that shows itself in daily, unobserved conduct.' },
  { id: 'q233', text: 'When you know a thing, to hold that you know it; and when you do not know a thing, to allow that you do not know it — this is knowledge.', attribution: 'Confucius', source: 'The Analects, 2.17', year: '~500 BCE', kind: 'philosopher', context: 'The calibration standard for any epistemic agent, biological or artificial.' },
  { id: 'q234', text: 'It does not matter how slowly you go as long as you do not stop.', attribution: 'Confucius (attrib.)', kind: 'philosopher', context: 'A useful counter when the pace of change in AI seems to require crisis responses.' },
  { id: 'q235', text: 'The superior man thinks always of virtue; the common man thinks of comfort.', attribution: 'Confucius', source: 'The Analects, 4.11', year: '~500 BCE', kind: 'philosopher', context: 'The design question Confucius asks of every system: is it building junzi — exemplary people — or consumers?' },
  { id: 'q236', text: 'To know the road ahead, ask those coming back.', attribution: 'Chinese proverb', kind: 'other', context: 'An argument for consulting the communities already living with a technology\'s consequences.' },
  { id: 'q237', text: 'An ounce of prevention is worth a pound of cure.', attribution: 'Benjamin Franklin', year: '1735', kind: 'other', context: 'The core argument for pre-deployment testing and red-teaming of AI systems.' },
  { id: 'q238', text: 'There is no such thing as a free lunch.', attribution: 'Robert A. Heinlein', source: 'The Moon Is a Harsh Mistress', year: '1966', kind: 'scifi-book', context: 'TANSTAAFL. Heinlein\'s principle applies to every claim of "free" digital service.' },
  { id: 'q239', text: 'Specialization is for insects.', attribution: 'Robert A. Heinlein', source: 'Time Enough for Love', year: '1973', kind: 'scifi-book', context: 'A call for broad competence. Uncomfortable for a profession that rewards narrow optimization.' },
  { id: 'q240', text: 'Never attribute to malice that which is adequately explained by a bug.', attribution: 'Modified Hanlon\'s Razor for software', kind: 'other', context: 'Also: never assume a bug cannot become malice once someone notices its utility.' },
  { id: 'q241', text: 'A ship in harbor is safe, but that is not what ships are built for.', attribution: 'John A. Shedd', source: 'Salt from My Attic', year: '1928', kind: 'other', context: 'A counter to pure-precaution positions in AI governance. Tools that are never used do not teach the society operating them.' },
  { id: 'q242', text: 'Fortune favors the prepared mind.', attribution: 'Louis Pasteur', source: 'Inaugural address, University of Lille', year: '1854', kind: 'scientist', context: 'Applies to organizations that invest in red-teaming, safety research, and institutional literacy before the crisis arrives.' },
  { id: 'q243', text: 'The race is not always to the swift, nor the battle to the strong, but that\'s the way to bet.', attribution: 'Damon Runyon (after Ecclesiastes)', kind: 'other', context: 'A useful prior when evaluating whether a well-resourced company with poor ethics will "lose in the long run." History suggests otherwise.' },
  { id: 'q244', text: 'An algorithm must be seen to be believed.', attribution: 'Donald Knuth', source: 'The Art of Computer Programming', year: '1968', kind: 'scientist', context: 'Knuth\'s call for visible, verifiable algorithms is increasingly difficult to honor in an era of proprietary ML systems.' },
  { id: 'q245', text: 'Premature optimization is the root of all evil.', attribution: 'Donald Knuth', source: 'Structured Programming with go to Statements', year: '1974', kind: 'scientist', context: 'The full quote is specific, but the principle generalizes: "optimize what is worth optimizing, not what is easiest to measure."' },
  { id: 'q246', text: 'Simplicity is prerequisite for reliability.', attribution: 'Edsger W. Dijkstra', source: 'How Do We Tell Truths That Might Hurt?', year: '1975', kind: 'scientist', context: 'Reliability is a safety property. Dijkstra\'s minimalism is not an aesthetic preference but an ethical stance.' },
  { id: 'q247', text: 'The competent programmer is fully aware of the strictly limited size of his own skull.', attribution: 'Edsger W. Dijkstra', source: '"The Humble Programmer"', year: '1972', kind: 'scientist', context: 'Dijkstra\'s humility as engineering virtue remains one of the most useful framings available.' },
  { id: 'q248', text: 'Testing can show the presence of bugs, but not their absence.', attribution: 'Edsger W. Dijkstra', source: 'Software Engineering Techniques', year: '1969', kind: 'scientist', context: 'Applies with particular force to probabilistic AI systems, whose failure modes are essentially combinatorial.' },
  { id: 'q249', text: 'It is practically impossible to teach good programming style to students that have had prior exposure to BASIC.', attribution: 'Edsger W. Dijkstra', year: '1975', kind: 'scientist', context: 'A provocation. The deeper claim — that early habits encode durable ethics — applies to any discipline.' },
  { id: 'q250', text: 'We can no longer afford to treat ethics as an optional seminar at the end of an engineering curriculum.', attribution: 'Modern restatement', kind: 'other', context: 'The single most-quoted sentiment in the AI-ethics reform literature. Rarely acted upon at scale.' },
  { id: 'q251', text: 'I am a part of all that I have met.', attribution: 'Tennyson', source: '"Ulysses"', year: '1842', kind: 'other', context: 'An argument that technology shapes users, whose surprise has been running since the Victorian era.' },
  { id: 'q252', text: 'We are such stuff as dreams are made on.', attribution: 'Prospero', source: 'The Tempest (Shakespeare)', year: '1611', kind: 'other', context: 'Quoted often on AI. The uncomfortable variant: we are such stuff as datasets are trained on.' },
  { id: 'q253', text: 'To be, or not to be: that is the question.', attribution: 'Hamlet', source: 'Hamlet (Shakespeare)', year: '1603', kind: 'other', context: 'The uploaded-consciousness question in seventeenth-century English. Whether continuation counts as continuation is still the question.' },
  { id: 'q254', text: 'Nothing will come of nothing.', attribution: 'King Lear', source: 'King Lear (Shakespeare)', year: '1606', kind: 'other', context: 'A useful reply to frameworks that promise value creation without corresponding extraction.' },
  { id: 'q255', text: 'Conscience doth make cowards of us all.', attribution: 'Hamlet', source: 'Hamlet (Shakespeare)', year: '1603', kind: 'other', context: 'Sometimes cowardice. Sometimes the institutional brake on catastrophe. The difference matters.' },
  { id: 'q256', text: 'We are not makers of history. We are made by history.', attribution: 'Martin Luther King Jr.', source: 'Strength to Love', year: '1963', kind: 'other', context: 'A check against technologist hubris. Civil society shapes technology as surely as technology shapes civil society.' },
  { id: 'q257', text: 'The arc of the moral universe is long, but it bends toward justice.', attribution: 'Theodore Parker, popularized by Martin Luther King Jr.', kind: 'other', context: 'Quoted often. The hidden premise is that someone has to bend it.' },
  { id: 'q258', text: 'Injustice anywhere is a threat to justice everywhere.', attribution: 'Martin Luther King Jr.', source: 'Letter from Birmingham Jail', year: '1963', kind: 'other', context: 'Applies with unusual specificity to global technology supply chains and algorithmic systems that act at planet scale.' },
  { id: 'q259', text: 'The ultimate measure of a man is not where he stands in moments of comfort and convenience, but where he stands at times of challenge and controversy.', attribution: 'Martin Luther King Jr.', source: 'Strength to Love', year: '1963', kind: 'other', context: 'Applies to technologists as individuals, and to institutions as collective actors.' },
  { id: 'q260', text: 'Our lives begin to end the day we become silent about things that matter.', attribution: 'Martin Luther King Jr.', kind: 'other', context: 'A test for every NDA, every code-of-silence, and every "we do not comment on internal matters" press statement.' },
  { id: 'q261', text: 'The future enters into us, in order to transform itself in us, long before it happens.', attribution: 'Rainer Maria Rilke', source: 'Letters to a Young Poet', year: '1929', kind: 'other', context: 'An argument that technological imagination is upstream of deployment. What we can picture is what we can eventually build.' },
  { id: 'q262', text: 'A system can never be stronger than its weakest link, and its weakest link is usually its assumptions.', attribution: 'Information security proverb', kind: 'other', context: 'Applies to AI alignment. Most alignment failure is assumption failure.' },
  { id: 'q263', text: 'Never interrupt your enemy when he is making a mistake.', attribution: 'Napoleon Bonaparte (attrib.)', kind: 'other', context: 'A useful counter to the reflex to engage every piece of bad technology discourse with correction.' },
  { id: 'q264', text: 'Bright light is the best disinfectant.', attribution: 'Louis Brandeis', source: '"What Publicity Can Do"', year: '1913', kind: 'other', context: 'The transparency argument in one line. Algorithmic systems test it harder than any institution Brandeis anticipated.' },
  { id: 'q265', text: 'Absolute honesty is much less demanding than the careful management of deception.', attribution: 'Jim Mattis (paraphrased)', kind: 'other', context: 'Applies to institutions with complicated disclosure positions. The upkeep is the real cost.' },
  { id: 'q266', text: 'Trust is the coin of the realm.', attribution: 'George Shultz', source: 'Hoover Institution essay', year: '2020', kind: 'other', context: 'The case for trust as a durable political-economic asset. Every design choice that erodes trust is drawing down a limited resource.' },
  { id: 'q267', text: 'An algorithm that can only explain itself is an algorithm whose output you cannot audit.', attribution: 'Anonymous', kind: 'other', context: 'The interpretability argument, compact form.' },
  { id: 'q268', text: 'An autonomous agent is still an agent. Who trained it and why are the first two questions, not the last two.', attribution: 'Anonymous restatement of Wells', kind: 'other', context: 'An argument against "the model decided" as a moral excuse.' },
  { id: 'q269', text: 'If a technology cannot be explained to a jury, it cannot be adopted by a democracy.', attribution: 'Anonymous restatement of Brandeis', kind: 'other', context: 'A strong and contested claim. Worth holding as an aspirational standard even when practice falls short.' },
  { id: 'q270', text: 'Surveillance is the business model of the internet.', attribution: 'Bruce Schneier', source: 'Data and Goliath', year: '2015', kind: 'scientist', context: 'Schneier\'s compact diagnosis. Every privacy discussion is operating on this terrain whether the participants admit it or not.' },
  { id: 'q271', text: 'Amateurs hack systems, professionals hack people.', attribution: 'Bruce Schneier', kind: 'scientist', context: 'The social-engineering insight. Applies to phishing, disinformation, and recommendation design.' },
  { id: 'q272', text: 'Security is a process, not a product.', attribution: 'Bruce Schneier', source: 'Crypto-Gram', year: '2000', kind: 'scientist', context: 'Applies to AI alignment. Shipping a model is the beginning of the safety work, not the end.' },
  { id: 'q273', text: 'If you think cryptography can solve your problem, then you don\'t understand your problem and you don\'t understand cryptography.', attribution: 'Roger Needham / Butler Lampson', kind: 'scientist', context: 'The same applies to "if you think AI can solve your problem."' },
  { id: 'q274', text: 'Biology is the most powerful technology ever created. DNA is software, proteins are hardware, cells are factories.', attribution: 'Arvind Gupta (attrib.)', kind: 'scientist', context: 'A claim that becomes more consequential as biotechnology matures. Policy is decades behind the capabilities.' },
  { id: 'q275', text: 'The cell is the soul of biology.', attribution: 'E. O. Wilson (paraphrased)', kind: 'scientist', context: 'A reminder for bioengineering ethics: the unit of moral attention is not the organism in the abstract but the cell in its context.' },
  { id: 'q276', text: 'The best way to predict the future is to prevent it.', attribution: 'Niels Bohr (attrib., paraphrased)', kind: 'scientist', context: 'Often cited by safety researchers. The original attribution is contested; the stance is coherent.' },
  { id: 'q277', text: 'It is no measure of health to be well adjusted to a profoundly sick society.', attribution: 'Jiddu Krishnamurti', kind: 'other', context: 'A useful counter when "the market wants this" is offered as ethical justification.' },
  { id: 'q278', text: 'The beginning is the most important part of the work.', attribution: 'Plato', source: 'The Republic, Book II', year: '~375 BCE', kind: 'philosopher', context: 'Applies to the training-data selection problem. The character of a system is set early, by what it is fed.' },
  { id: 'q279', text: 'Ignorance, the root and stem of all evil.', attribution: 'Plato', source: 'Apology', year: '399 BCE', kind: 'philosopher', context: 'An argument against the view that ignorance is neutral. Training data gaps are not morally neutral.' },
  { id: 'q280', text: 'Music gives a soul to the universe, wings to the mind, flight to the imagination and life to everything.', attribution: 'Plato (attrib.)', kind: 'philosopher', context: 'Quoted for the argument that aesthetic and moral development are intertwined — a useful reframe for "ethics and design."' },
  { id: 'q281', text: 'The direction in which education starts a man will determine his future life.', attribution: 'Plato', source: 'The Republic', year: '~375 BCE', kind: 'philosopher', context: 'Applies to training in general, human and machine. The conditions of formation matter far more than later corrections.' },
  { id: 'q282', text: 'Good people do not need laws to tell them to act responsibly, while bad people will find a way around the laws.', attribution: 'Plato', source: 'The Republic (paraphrased)', year: '~375 BCE', kind: 'philosopher', context: 'A check on regulatory optimism. Laws are necessary but not sufficient.' },
  { id: 'q283', text: 'The greatest wealth is to live content with little.', attribution: 'Plato (attrib.)', kind: 'philosopher', context: 'A counter to the unbounded-growth assumption built into most technology-product roadmaps.' },
  { id: 'q284', text: 'There is nothing permanent except change.', attribution: 'Heraclitus', year: '~500 BCE', kind: 'philosopher', context: 'A calibration for any technology-ethics framework that assumes a stable target.' },
  { id: 'q285', text: 'No man ever steps in the same river twice, for it is not the same river and he is not the same man.', attribution: 'Heraclitus', year: '~500 BCE', kind: 'philosopher', context: 'Applies to users and to systems. The model you deploy and the model your users interact with are not the same model at inference time.' },
  { id: 'q286', text: 'Character is destiny.', attribution: 'Heraclitus', year: '~500 BCE', kind: 'philosopher', context: 'A virtue-ethics claim that applies to organizations. What a company is becomes what it does, however it rebrands.' },
  { id: 'q287', text: 'Where there is no vision, the people perish.', attribution: 'Proverbs 29:18', kind: 'other', context: 'Applies to technology roadmaps. Execution without a vision of the good life is drift at high speed.' },
  { id: 'q288', text: 'What has been will be again, what has been done will be done again; there is nothing new under the sun.', attribution: 'Ecclesiastes 1:9', kind: 'other', context: 'A humbling posture for a field that regularly discovers problems that moral philosophers and theologians named centuries ago.' },
  { id: 'q289', text: 'The man who moves a mountain begins by carrying away small stones.', attribution: 'Confucius (attrib.)', kind: 'philosopher', context: 'An argument for the small, sustained, specific work of technology ethics, against the temptation of grand theory alone.' },
  { id: 'q290', text: 'No matter how old a mother is, she watches her middle-aged children for signs of improvement.', attribution: 'Florida Scott-Maxwell', kind: 'other', context: 'A warm reframe for the long-horizon work of raising a technology or a field — the observation that growth is incremental and constant.' },
  { id: 'q291', text: 'Happiness is when what you think, what you say, and what you do are in harmony.', attribution: 'Mahatma Gandhi', kind: 'other', context: 'The alignment principle, applied to individuals. Organizations that misalign the three produce the costs we now debate.' },
  { id: 'q292', text: 'In a gentle way, you can shake the world.', attribution: 'Mahatma Gandhi', kind: 'other', context: 'A counter-style argument for the power of non-spectacular technology ethics work.' },
  { id: 'q293', text: 'Do not resist evil; overcome evil with good.', attribution: 'Romans 12:21 (paraphrased)', kind: 'other', context: 'Quoted as a constructive reframe. Technology-ethics work that only opposes rarely builds the replacement.' },
  { id: 'q294', text: 'The hottest places in hell are reserved for those who, in times of great moral crisis, maintain their neutrality.', attribution: 'Dante Alighieri (attrib., later invented)', kind: 'other', context: 'Wrongly attributed to Dante. Often quoted nonetheless. The sentiment has force against "just following orders" defenses in tech deployment.' },
  { id: 'q295', text: 'The only thing necessary for the triumph of evil is for good men to do nothing.', attribution: 'Attrib. Edmund Burke (not found in his writings)', kind: 'other', context: 'Apocryphal but politically durable. Applies to engineer refusal, whistle-blowing, and institutional accountability.' },
  { id: 'q296', text: 'Knowledge without conscience is but the ruin of the soul.', attribution: 'François Rabelais', source: 'Gargantua', year: '1534', kind: 'philosopher', context: 'A five-hundred-year-old warning against the technical-education-without-ethics model.' },
  { id: 'q297', text: 'It is impossible for a man to learn what he thinks he already knows.', attribution: 'Epictetus', source: 'Discourses', year: '~100 CE', kind: 'philosopher', context: 'Stoic epistemology as design principle. Systems that assume their users need no update from them will not update themselves either.' },
  { id: 'q298', text: 'Man is disturbed not by things, but by the views he takes of them.', attribution: 'Epictetus', source: 'Enchiridion', year: '~125 CE', kind: 'philosopher', context: 'The Stoic framing is a useful counter to the claim that user reactions to technology are mere irrationality.' },
  { id: 'q299', text: 'Waste no more time arguing what a good man should be. Be one.', attribution: 'Marcus Aurelius', source: 'Meditations, 10.16', year: '~170 CE', kind: 'philosopher', context: 'A Stoic argument against over-theorization. Applies to engineers who debate ethics but do not change their ship list.' },
  { id: 'q300', text: 'The universe is change; our life is what our thoughts make it.', attribution: 'Marcus Aurelius', source: 'Meditations, 4.3', year: '~170 CE', kind: 'philosopher', context: 'Applies to organizations: what an institution chooses to notice becomes the institution\'s life.' },
  { id: 'q301', text: 'It is not death that a man should fear, but he should fear never beginning to live.', attribution: 'Marcus Aurelius', source: 'Meditations', year: '~170 CE', kind: 'philosopher', context: 'A counter to precautionary paralysis in technology work.' },
  { id: 'q302', text: 'You have power over your mind — not outside events. Realize this, and you will find strength.', attribution: 'Marcus Aurelius', source: 'Meditations', year: '~170 CE', kind: 'philosopher', context: 'The Stoic frame for technologists operating inside systems they cannot unilaterally change: focus on the work you actually control.' },
  { id: 'q303', text: 'Accept the things to which fate binds you, and love the people with whom fate brings you together, and do so with all your heart.', attribution: 'Marcus Aurelius', source: 'Meditations, 6.39', year: '~170 CE', kind: 'philosopher', context: 'Applies unexpectedly well to the daily moral texture of working inside a technology company.' },
  { id: 'q304', text: 'We suffer more often in imagination than in reality.', attribution: 'Seneca', source: 'Letters from a Stoic', year: '~65 CE', kind: 'philosopher', context: 'Useful against the reflex pessimism in some AI-doom discourse — and against the reflex dismissal of caution as "imagined."' },
  { id: 'q305', text: 'Luck is what happens when preparation meets opportunity.', attribution: 'Seneca', kind: 'philosopher', context: 'Applies to organizations that invest in ethics and safety work before the incident occurs.' },
  { id: 'q306', text: 'Every new beginning comes from some other beginning\'s end.', attribution: 'Seneca', kind: 'philosopher', context: 'Quoted by Semisonic. Always true of technology transitions.' },
  { id: 'q307', text: 'True ignorance is not the absence of knowledge, but the refusal to acquire it.', attribution: 'Karl Popper (paraphrased)', kind: 'philosopher', context: 'Applies to institutions that have the information and do not act on it.' },
  { id: 'q308', text: 'Science must begin with myths, and with the criticism of myths.', attribution: 'Karl Popper', source: 'Conjectures and Refutations', year: '1963', kind: 'philosopher', context: 'A useful framing of the relationship between speculative fiction and scientific research programs.' },
  { id: 'q309', text: 'Whenever a theory appears to you as the only possible one, take this as a sign that you have neither understood the theory nor the problem which it was intended to solve.', attribution: 'Karl Popper', source: 'Objective Knowledge', year: '1972', kind: 'philosopher', context: 'Essential calibration for AI-ethics frameworks that claim unique adequacy.' },
  { id: 'q310', text: 'Unlimited tolerance must lead to the disappearance of tolerance.', attribution: 'Karl Popper', source: 'The Open Society and Its Enemies, footnote 4', year: '1945', kind: 'philosopher', context: 'The paradox of tolerance. Applies to content moderation, platform governance, and open protocols.' },
  { id: 'q311', text: 'Political power is never held by those who seem to hold it; it is always held by those who own the conditions of speech.', attribution: 'Modern restatement of Foucault', kind: 'philosopher', context: 'Applies to platform governance: ownership of the speech substrate is political power regardless of the legal framing.' },
  { id: 'q312', text: 'We live in a society exquisitely dependent on science and technology, in which hardly anyone knows anything about science and technology.', attribution: 'Carl Sagan', source: 'The Demon-Haunted World', year: '1995', kind: 'scientist', context: 'The civic-literacy problem at the heart of democratic technology governance.' },
  { id: 'q313', text: 'Extraordinary claims require extraordinary evidence.', attribution: 'Carl Sagan (Sagan Standard)', kind: 'scientist', context: 'Applies to every AI capability announcement. Benchmarks are not evidence of the claim made about the benchmark.' },
  { id: 'q314', text: 'Somewhere, something incredible is waiting to be known.', attribution: 'Carl Sagan (attrib.)', kind: 'scientist', context: 'Balances this collection\'s caution with a reminder of why the work is worth the care.' },
  { id: 'q315', text: 'For small creatures such as we, the vastness is bearable only through love.', attribution: 'Carl Sagan', source: 'Contact', year: '1985', kind: 'scifi-book', context: 'Sagan\'s SF novel closes with this line. Applies to the scale of the governance problem we have inherited.' },
  { id: 'q316', text: 'We are, each of us, a little universe.', attribution: 'Neil deGrasse Tyson', source: 'Cosmos (2014)', year: '2014', kind: 'scientist', context: 'A reminder that "users at scale" are each a full subject, not a data point.' },
  { id: 'q317', text: 'The dose makes the poison.', attribution: 'Paracelsus (paraphrased)', year: '~1540', kind: 'scientist', context: 'The oldest principle of pharmacology applies directly to platform exposure, addictive design, and cumulative effects of recommendation.' },
  { id: 'q318', text: 'To find yourself, think for yourself.', attribution: 'Socrates (attrib.)', kind: 'philosopher', context: 'An older version of "don\'t outsource your cognition to the feed."' },
  { id: 'q319', text: 'The only lasting beauty is the beauty of the heart.', attribution: 'Rumi', kind: 'other', context: 'A counter to aesthetic-as-ethics claims in product design. Interface polish does not substitute for substance.' },
  { id: 'q320', text: 'Out beyond ideas of wrongdoing and rightdoing, there is a field. I\'ll meet you there.', attribution: 'Rumi', kind: 'other', context: 'Quoted against the reflex to reduce ethics to binary compliance.' },
  { id: 'q321', text: 'Everything in excess is opposed to nature.', attribution: 'Hippocrates', source: 'Aphorisms', year: '~400 BCE', kind: 'scientist', context: 'Applies to engagement metrics, to attention, to notification volume. The Hippocratic maxim translates forward.' },
  { id: 'q322', text: 'First, do no harm.', attribution: 'Modernization of the Hippocratic oath', year: '~19th century', kind: 'scientist', context: 'The strongest short framing of the case for pre-deployment safety evaluation in AI.' },
  { id: 'q323', text: 'Cura te ipsum — physician, heal thyself.', attribution: 'Luke 4:23', kind: 'other', context: 'Applies to the AI safety field, to regulators, to journalists. Everybody working on the problem is also inside the system the problem describes.' },
  { id: 'q324', text: 'The most beautiful things in the world cannot be seen or touched; they must be felt with the heart.', attribution: 'Antoine de Saint-Exupéry', source: 'The Little Prince', year: '1943', kind: 'scifi-book', context: 'A counter to the assumption that anything that matters can be measured.' },
  { id: 'q325', text: 'What is essential is invisible to the eye.', attribution: 'The fox', source: 'The Little Prince (Saint-Exupéry)', year: '1943', kind: 'scifi-book', context: 'The fox\'s lesson, quoted in every discussion of metrics. The thing you can measure is rarely the thing you care about.' },
  { id: 'q326', text: 'Grown-ups never understand anything by themselves, and it is exhausting for children to be always and forever explaining things to them.', attribution: 'The narrator', source: 'The Little Prince (Saint-Exupéry)', year: '1943', kind: 'scifi-book', context: 'Applies with unexpected force to the work of explaining algorithmic systems to the institutions that deploy them.' },
  { id: 'q327', text: 'If you want to build a ship, don\'t drum up people to collect wood and don\'t assign them tasks and work, but rather teach them to long for the endless immensity of the sea.', attribution: 'Antoine de Saint-Exupéry (paraphrased)', kind: 'other', context: 'An argument for vision over specification in technology projects — and a cautionary tale about crews that follow the vision past the harbor.' },
  { id: 'q328', text: 'Perfection is achieved, not when there is nothing more to add, but when there is nothing left to take away.', attribution: 'Antoine de Saint-Exupéry', source: 'Wind, Sand and Stars', year: '1939', kind: 'other', context: 'Applies with peculiar force to system design. Every additional surface is an additional attack surface.' },
  { id: 'q329', text: 'You become responsible, forever, for what you have tamed.', attribution: 'Saint-Exupéry\'s fox (again)', source: 'The Little Prince', year: '1943', kind: 'scifi-book', context: 'Quoted twice in this collection because it is the single clearest statement of creator-responsibility available in fiction.' },
  { id: 'q330', text: 'Begin at the beginning, the King said gravely, and go on till you come to the end: then stop.', attribution: 'Lewis Carroll', source: 'Alice in Wonderland', year: '1865', kind: 'other', context: 'A joke. Also a call for specification clarity that would save most machine-learning projects from most of their pain.' },
  { id: 'q331', text: 'Sometimes I\'ve believed as many as six impossible things before breakfast.', attribution: 'The White Queen', source: 'Through the Looking-Glass (Carroll)', year: '1871', kind: 'other', context: 'The attitude a product manager needs. Also the attitude that produces most ethical disasters.' },
  { id: 'q332', text: 'If you don\'t know where you are going, any road will get you there.', attribution: 'Lewis Carroll (paraphrased)', source: 'Alice in Wonderland', year: '1865', kind: 'other', context: 'A specification problem in fable form.' },
  { id: 'q333', text: 'Curiouser and curiouser.', attribution: 'Alice', source: 'Alice in Wonderland (Carroll)', year: '1865', kind: 'other', context: 'A useful epistemic stance when the logs get stranger than the spec.' },
  { id: 'q334', text: 'In the end, we are all atoms strumming on a quantum guitar.', attribution: 'Contemporary physics gloss', kind: 'other', context: 'Quoted for the reminder that reductive framings of persons as data points are precisely as valid as reductive framings of persons as atoms — which is, for ethical purposes, not very.' },
  { id: 'q335', text: 'Reality has a surprising amount of detail.', attribution: 'John Salvatier', source: 'johnsalvatier.org', year: '2017', kind: 'scientist', context: 'A programmer\'s observation that every abstraction leaks. The implication for automated decision-making is severe.' },
  { id: 'q336', text: 'We are drowning in information, while starving for wisdom.', attribution: 'E. O. Wilson', source: 'Consilience', year: '1998', kind: 'scientist', context: 'The gap Wilson identified has widened, not closed. Addressing it is one of the central tasks of technology education.' },
  { id: 'q337', text: 'It is better to ask some of the questions than to know all the answers.', attribution: 'James Thurber', kind: 'other', context: 'Applies to the design of AI systems that increasingly deliver confident answers to poorly-posed questions.' },
  { id: 'q338', text: 'Ethics is the aesthetic of the future.', attribution: 'Lenin (attrib., context disputed)', kind: 'other', context: 'Worth holding as an aspirational frame: what we consider beautiful tomorrow will be a function of what we consider good today.' },
  { id: 'q339', text: 'The poorest man is he who has only money.', attribution: 'Unknown', kind: 'other', context: 'A useful counter to the reductive metrics by which technology success is usually measured.' },
  { id: 'q340', text: 'We are born weak, we need strength; helpless, we need aid; foolish, we need reason. All that we lack at birth, all that we need when we come to man\'s estate, is the gift of education.', attribution: 'Jean-Jacques Rousseau', source: 'Emile', year: '1762', kind: 'philosopher', context: 'Applies to human development and to the development of large models. Both require curated formation over substantial time.' },
  { id: 'q341', text: 'Man is born free, and everywhere he is in chains.', attribution: 'Jean-Jacques Rousseau', source: 'The Social Contract', year: '1762', kind: 'philosopher', context: 'The opening sentence of The Social Contract. Applies to the constrained autonomy modern digital citizens actually exercise.' },
  { id: 'q342', text: 'The foundation of every state is the education of its youth.', attribution: 'Diogenes', kind: 'philosopher', context: 'The education we are giving to foundation models is, for better or worse, setting the terms of the next century of political life.' },
  { id: 'q343', text: 'Give me a child for the first seven years, and I will give you the man.', attribution: 'Aristotle (attrib.)', kind: 'philosopher', context: 'Applies to training-data regimes. The character of a system is set early by what it sees.' },
  { id: 'q344', text: 'The city is not made of stone. It is made of decisions.', attribution: 'Jane Jacobs (paraphrased)', kind: 'scientist', context: 'So is the feed. So is the platform. So is the AI system.' },
  { id: 'q345', text: 'Eyes on the street.', attribution: 'Jane Jacobs', source: 'The Death and Life of Great American Cities', year: '1961', kind: 'scientist', context: 'Jacobs\'s principle of diffuse ambient observation in safe cities. Applies with adaptation to the social infrastructure of trustworthy platforms.' },
  { id: 'q346', text: 'If you always do what you always did, you\'ll always get what you always got.', attribution: 'Henry Ford (attrib.)', kind: 'other', context: 'Applies to institutional responses to AI capabilities. Doing what worked last time will not work this time.' },
  { id: 'q347', text: 'The best minds of my generation are thinking about how to make people click ads.', attribution: 'Jeff Hammerbacher', source: 'Bloomberg Businessweek', year: '2011', kind: 'scientist', context: 'Hammerbacher\'s lament about the allocation of technical talent is still accurate. The targets have updated; the pattern has not.' },
  { id: 'q348', text: 'The real danger is not that computers will begin to think like men, but that men will begin to think like computers.', attribution: 'Sydney J. Harris', year: '1979', kind: 'other', context: 'A 1979 claim that reads now as a daily diagnosis of platform-mediated cognition.' },
  { id: 'q349', text: 'A computer can never be held accountable, therefore a computer must never make a management decision.', attribution: 'IBM training manual', year: '1979', kind: 'other', context: 'A 1979 IBM rule, often quoted in AI-accountability debates. Its wisdom has held up.' },
  { id: 'q350', text: 'Whom the gods would destroy, they first make mad.', attribution: 'Euripides (paraphrased)', kind: 'other', context: 'Applies to the recursive loops in algorithmic systems that amplify their own feedback to destructive thresholds.' },
  { id: 'q351', text: 'The most dangerous phrase in the language is: "We\'ve always done it this way."', attribution: 'Grace Hopper', kind: 'scientist', context: 'Hopper\'s rule. Also a useful counter to institutional defenses of ethically questionable defaults.' },
  { id: 'q352', text: 'The most damaging phrase in the language is: "It\'s always been done that way."', attribution: 'Grace Hopper (alt. version)', kind: 'scientist', context: 'Same principle, slightly different phrasing. Worth both hearings.' },
  { id: 'q353', text: 'Humans are allergic to change. They love to say, \'We\'ve always done it this way.\' I try to fight that.', attribution: 'Grace Hopper', source: 'Chips Magazine interview', year: '1986', kind: 'scientist', context: 'Hopper\'s institutional honesty about the difficulty of changing engineering defaults.' },
  { id: 'q354', text: 'A ship in port is safe, but that\'s not what ships are built for. Sail out to sea and do new things.', attribution: 'Grace Hopper', kind: 'scientist', context: 'Hopper\'s version of the Shedd quote. Applied with her engineering practice, not as excuse for recklessness.' },
  { id: 'q355', text: 'Education is not the filling of a pail, but the lighting of a fire.', attribution: 'William Butler Yeats (attrib., disputed)', kind: 'other', context: 'Applies to human and machine learning both. Retrieval-augmented generation is pail-filling; curiosity is fire-lighting.' },
  { id: 'q356', text: 'Tell me and I forget. Teach me and I remember. Involve me and I learn.', attribution: 'Benjamin Franklin (attrib.)', kind: 'other', context: 'The design principle for ethics education inside a technology company.' },
  { id: 'q357', text: 'Whatever you are, be a good one.', attribution: 'Abraham Lincoln (attrib.)', kind: 'other', context: 'The virtue-ethics stance. Applies to careers in technology: the ethics of your job is how you do the job.' },
  { id: 'q358', text: 'I disapprove of what you say, but I will defend to the death your right to say it.', attribution: 'Evelyn Beatrice Hall summarizing Voltaire', source: 'The Friends of Voltaire', year: '1906', kind: 'other', context: 'A principle the contemporary content-moderation debate tests. Worth holding while acknowledging that the application conditions have changed.' },
  { id: 'q359', text: 'The greatest glory in living lies not in never falling, but in rising every time we fall.', attribution: 'Nelson Mandela', kind: 'other', context: 'Applies to institutions as much as to people. A company whose ethics records admits failures is a company with a chance to improve.' },
  { id: 'q360', text: 'I never lose. I either win or I learn.', attribution: 'Nelson Mandela (attrib.)', kind: 'other', context: 'Frequently misattributed. The sentiment is useful in post-incident reviews if taken seriously rather than as marketing copy.' },
  { id: 'q361', text: 'Only to the extent that we expose ourselves over and over to annihilation can that which is indestructible be found in us.', attribution: 'Pema Chödrön', source: 'When Things Fall Apart', year: '1997', kind: 'other', context: 'An unusual frame for safety-critical work: the real safety comes from honest encounter with failure, not from its concealment.' },
  { id: 'q362', text: 'I can resist anything except temptation.', attribution: 'Oscar Wilde', source: 'Lady Windermere\'s Fan', year: '1892', kind: 'other', context: 'A line that describes the daily condition of operators of engagement-optimized platforms.' },
  { id: 'q363', text: 'Life imitates art far more than art imitates life.', attribution: 'Oscar Wilde', source: '"The Decay of Lying"', year: '1891', kind: 'other', context: 'Applies with unusual specificity to technology: products are often built to realize scenarios that first appeared in fiction.' },
  { id: 'q364', text: 'Be yourself; everyone else is already taken.', attribution: 'Oscar Wilde (attrib.)', kind: 'other', context: 'A reply to algorithmic recommendation systems that flatten users into the median behavior of their cohort.' },
  { id: 'q365', text: 'It is only shallow people who do not judge by appearances. The true mystery of the world is the visible, not the invisible.', attribution: 'Oscar Wilde', source: 'The Picture of Dorian Gray', year: '1890', kind: 'other', context: 'A useful corrective for technology ethics: the visible texture of an interface is a moral fact, not a cosmetic one.' },
  { id: 'q366', text: 'The best way to take care of the future is to take care of the present moment.', attribution: 'Thich Nhat Hanh', kind: 'philosopher', context: 'An engaged-Buddhist framing of long-horizon work. Applies to climate, AI, and the people you work with today.' },
  { id: 'q367', text: 'If you think you are too small to make a difference, try sleeping with a mosquito.', attribution: 'Dalai Lama (attrib.)', kind: 'other', context: 'A counter to the "I am just one engineer" defense. Small interventions at scale are exactly what infrastructure technology is.' },
];

/** Deterministic day-of-year → quote index. UTC-based so all clients
 *  see the same quote on a given calendar day. Wraps with modulo so
 *  adding quotes never breaks the rotation. */
export function quoteIndexForDate(date: Date = new Date()): number {
  const start = Date.UTC(date.getUTCFullYear(), 0, 0);
  const now = Date.UTC(
    date.getUTCFullYear(),
    date.getUTCMonth(),
    date.getUTCDate()
  );
  const dayOfYear = Math.floor((now - start) / 86400000);
  return ((dayOfYear - 1) % techEthicsQuotes.length + techEthicsQuotes.length) %
    techEthicsQuotes.length;
}

export function getQuoteOfTheDay(date: Date = new Date()): TechEthicsQuote {
  return techEthicsQuotes[quoteIndexForDate(date)];
}
